1	/**
2	 * Per-cycle in_review PR status poller.
3	 *
4	 * For every `in_review` task across all watched workspaces, calls the GitHub
5	 * GraphQL API to fetch: mergeable state, draft state, and unresolved inline
6	 * review threads.
7	 *
8	 * General PR-level issue comments are intentionally ignored — they are not
9	 * trackable without identity-dependent heuristics and cause dispatch loops.
10	 * Only inline review threads (which have a first-class `isResolved` bit on
11	 * GitHub's side) are used to determine whether a review agent should run.
12	 *
13	 * Pure read — no task YAML mutations.
14	 *
15	 * On API errors, emits `in_review_poll_error` and skips that task.
16	 * Results are passed to the T3 (auto-rebase) and T4 (open-comment) handlers.
17	 */
18	
19	import { existsSync, readFileSync, readdirSync } from "node:fs";
20	import { join } from "node:path";
21	import { spawnSync } from "node:child_process";
22	import { parse as parseYaml } from "yaml";
23	import type { Task } from "../types/task.js";
24	import { featuresRoot, TASKS_DIR, taskBranchName, taskYamlRelPath } from "../paths.js";
25	import { TERMINAL_STATUSES, tryReadTaskFromBranch } from "../task-branch-state.js";
26	
27	// ── Public types ──────────────────────────────────────────────────────────────
28	
29	/** Status reported by the GitHub GraphQL API for a single in_review task's PR. */
30	export interface PrStatusResult {
31	  taskId: string;
32	  featureId: string;
33	  /** Absolute path to the management workspace that owns this task. */
34	  workspaceRoot: string;
35	  /**
36	   * Whether the PR can be cleanly merged into the base branch.
37	   * null means GitHub has not finished computing the mergeability yet.
38	   */
39	  mergeable: boolean | null;
40	  /** True when the PR is in draft state. */
41	  draft: boolean;
42	  /**
43	   * True when the PR has at least one unresolved inline review thread.
44	   * General PR-level issue comments are not tracked.
45	   * This is the trigger for dispatching the respond-to-review agent.
46	   */
47	  hasOpenComments: boolean;
48	}
49	
50	export interface CheckInReviewPrsOptions {
51	  /** Absolute paths to management workspace repos to scan. */
52	  workspaceRoots: string[];
53	  /** GitHub personal access token for API authentication. */
54	  githubToken: string;
55	  emit: (event: Record<string, unknown>) => void;
56	}
57	
58	// ── Internal helpers ──────────────────────────────────────────────────────────
59	
60	/**
61	 * Parse owner, repo, and pull number from a GitHub PR URL.
62	 * Accepts https://github.com/{owner}/{repo}/pull/{number}
63	 * Returns null for any non-matching URL.
64	 */
65	export function parsePrUrl(
66	  url: string,
67	): { owner: string; repo: string; pullNumber: number } | null {
68	  const match = /https?:\/\/github\.com\/([^/]+)\/([^/]+)\/pull\/(\d+)/.exec(url);
69	  if (!match) return null;
70	  return {
71	    owner: match[1],
72	    repo: match[2],
73	    pullNumber: parseInt(match[3], 10),
74	  };
75	}
76	
77	interface GitHubGraphQLPrData {
78	  isDraft: boolean;
79	  mergeable: "MERGEABLE" | "CONFLICTING" | "UNKNOWN";
80	  reviewThreads: { nodes: Array<{ isResolved: boolean }> };
81	}
82	
83	interface GitHubGraphQLResponse {
84	  data?: { repository?: { pullRequest?: GitHubGraphQLPrData | null } | null };
85	  errors?: Array<{ message: string }>;
86	}
87	
88	const PR_STATUS_QUERY = `
89	query($owner: String!, $name: String!, $number: Int!) {
90	  repository(owner: $owner, name: $name) {
91	    pullRequest(number: $number) {
92	      isDraft
93	      mergeable
94	      reviewThreads(first: 100) { nodes { isResolved } }
95	    }
96	  }
97	}`.trim();
98	
99	/**
100	 * Call the GitHub GraphQL API via curl to get PR status and unresolved review threads.
101	 * Throws on curl failure, empty response, or GraphQL errors.
102	 */
103	function fetchPrStatus(
104	  owner: string,
105	  repo: string,
106	  pullNumber: number,
107	  githubToken: string,
108	): { draft: boolean; mergeable: boolean | null; hasOpenComments: boolean } {
109	  const body = JSON.stringify({
110	    query: PR_STATUS_QUERY,
111	    variables: { owner, name: repo, number: pullNumber },
112	  });
113	
114	  const result = spawnSync(
115	    "curl",
116	    [
117	      "-s", "-X", "POST",
118	      "-H", `Authorization: Bearer ${githubToken}`,
119	      "-H", "Content-Type: application/json",
120	      "-H", "Accept: application/vnd.github+json",
121	      "-d", body,
122	      "https://api.github.com/graphql",
123	    ],
124	    { encoding: "utf-8", stdio: ["ignore", "pipe", "pipe"] },
125	  );
126	
127	  if (result.error) throw result.error;
128	  const stdout = result.stdout ?? "";
129	  if (!stdout.trim()) throw new Error(`curl returned empty response. stderr: ${result.stderr ?? ""}`);
130	
131	  const gql = JSON.parse(stdout) as GitHubGraphQLResponse;
132	  if (gql.errors?.length) {
133	    throw new Error(`GraphQL errors: ${gql.errors.map((e) => e.message).join("; ")}`);
134	  }
135	
136	  const pr = gql.data?.repository?.pullRequest;
137	  if (!pr) throw new Error("GraphQL response missing pullRequest data");
138	
139	  const mergeableRaw = pr.mergeable;
140	  const mergeable =
141	    mergeableRaw === "MERGEABLE" ? true :
142	    mergeableRaw === "CONFLICTING" ? false : null;
143	
144	  const hasOpenComments = pr.reviewThreads.nodes.some((t) => !t.isResolved);
145	
146	  return {
147	    draft: pr.isDraft,
148	    mergeable,
149	    hasOpenComments,
150	  };
151	}
152	
