154	// ── Public API ────────────────────────────────────────────────────────────────
155	
156	/**
157	 * Scan all watched workspaces for `in_review` tasks whose PR URL is set,
158	 * then call the GitHub API for each to get current mergeability and draft state.
159	 *
160	 * Returns one `PrStatusResult` per task successfully polled.
161	 * Tasks with API errors or unparseable PR URLs are skipped (error emitted).
162	 */
163	export async function checkInReviewPrs(
164	  opts: CheckInReviewPrsOptions,
165	): Promise<PrStatusResult[]> {
166	  const { workspaceRoots, githubToken, emit } = opts;
167	  const results: PrStatusResult[] = [];
168	
169	  for (const workspaceRoot of workspaceRoots) {
170	    const docsPath = featuresRoot(workspaceRoot);
171	    if (!existsSync(docsPath)) continue;
172	
173	    let featureDirs: string[];
174	    try {
175	      featureDirs = readdirSync(docsPath, { withFileTypes: true })
176	        .filter((e) => e.isDirectory())
177	        .map((e) => e.name);
178	    } catch {
179	      continue;
180	    }
181	
182	    for (const featureId of featureDirs) {
183	      const tasksDir = join(docsPath, featureId, TASKS_DIR);
184	      if (!existsSync(tasksDir)) continue;
185	
186	      let taskFiles: string[];
187	      try {
188	        taskFiles = readdirSync(tasksDir).filter((f) =>
189	          /^T\d+\.yaml$/.test(f),
190	        );
191	      } catch {
192	        continue;
193	      }
194	
195	      for (const fileName of taskFiles) {
196	        let task: Task;
197	        try {
198	          task = parseYaml(
199	            readFileSync(join(tasksDir, fileName), "utf-8"),
200	          ) as Task;
201	        } catch {
202	          continue;
203	        }
204	
205	        // If the task is in-flight on main, the live state is on the feature branch.
206	        // If the branch doesn't exist yet, there's nothing to poll — skip.
207	        if (!TERMINAL_STATUSES.has(task.status)) {
208	          const taskId = fileName.replace(/\.yaml$/, "");
209	          const branch = taskBranchName(featureId, taskId);
210	          const relPath = taskYamlRelPath(featureId, taskId);
211	          const branchTask = tryReadTaskFromBranch(workspaceRoot, branch, relPath);
212	          if (!branchTask) continue;
213	          task = branchTask;
214	        }
215	
216	        // Only poll in_review tasks with a PR URL set.
217	        if (task.status !== "in_review") continue;
218	        if (!task.pr?.url) continue;
219	
220	        const coords = parsePrUrl(task.pr.url);
221	        if (!coords) {
222	          emit({
223	            type: "in_review_poll_error",
224	            task_id: task.id,
225	            feature_id: featureId,
226	            details: `Cannot parse PR URL: ${task.pr.url}`,
227	          });
228	          continue;
229	        }
230	
231	        try {
232	          const prStatus = fetchPrStatus(
233	            coords.owner,
234	            coords.repo,
235	            coords.pullNumber,
236	            githubToken,
237	          );
238	
239	          results.push({
240	            taskId: task.id,
241	            featureId,
242	            workspaceRoot,
243	            mergeable: prStatus.mergeable,
244	            draft: prStatus.draft,
245	            hasOpenComments: prStatus.hasOpenComments,
246	          });
247	        } catch (e) {
248	          emit({
249	            type: "in_review_poll_error",
250	            task_id: task.id,
251	            feature_id: featureId,
252	            details: String(e),
253	          });
254	        }
255	      }
256	    }
257	  }
258	
259	  return results;
260	}
