import { spawnSync } from "child_process";
import { parse as parseYaml } from "yaml";
import type { Task } from "./types/task.js";

/** Statuses where the authoritative state lives on main, not a feature branch. */
export const TERMINAL_STATUSES = new Set(["todo", "done", "cancelled"]);

/**
 * Try to read a task YAML from `origin/<branch>` via `git show`.
 * Returns null if the branch or file does not exist.
 */
export function tryReadTaskFromBranch(
  workspaceRoot: string,
  branch: string,
  relPath: string,
): Task | null {
  const result = spawnSync(
    "git",
    ["-C", workspaceRoot, "show", `origin/${branch}:${relPath}`],
    { encoding: "utf-8", stdio: ["ignore", "pipe", "pipe"] },
  );
  if (result.status !== 0 || !result.stdout.trim()) return null;
  try {
    return parseYaml(result.stdout) as Task;
  } catch {
    return null;
  }
}

