1	/** Task lifecycle statuses. */
2	export type TaskStatus =
3	  | "todo"
4	  | "ready"
5	  | "in_progress"
6	  | "blocked"
7	  | "in_review"
8	  | "done"
9	  | "cancelled";
10	
11	/** Reasons a task may be blocked. Written to task.yaml when status becomes blocked. */
12	export type BlockedReason =
13	  | "budget_exceeded"
14	  | "iteration_cap_exceeded"
15	  | "no_progress"
16	  | "model_escalation_requested"
17	  | "skill_missing"
18	  | "runtime_error"
19	  | "pr_conflict";
20	
21	/** Who may execute a task. */
22	export type ActorType = "human" | "agent" | "either";
23	
24	/**
25	 * Tracks the mergeability lifecycle of a task's implementation PR.
26	 * Written to `conflict_state` on the task YAML when the polling loop detects
27	 * a conflict or when the rebase handler updates resolution progress.
28	 */
29	export type ConflictState = "none" | "conflicted" | "resolving" | "resolved";
30	
31	/** One entry in the append-only rebase audit log stored on the task. */
32	export interface RebaseLogEntry {
33	  /** ISO-8601 timestamp when this entry was written. */
34	  at: string;
35	  /** What the rebase handler did or observed at this point. */
36	  action: "rebase_started" | "rebase_completed" | "rebase_blocked" | "rebase_resolved_by_agent";
37	  /** Agent email or actor identifier that wrote this entry. */
38	  by: string;
39	  /** Human-readable detail — e.g. file:line pointers for conflicted hunks. */
40	  note?: string;
41	}
42	
43	/** Pull-request lifecycle state. */
44	export type PrStatus = "not_created" | "open" | "merged" | "closed";
45	
46	/** One entry in the task's append-only audit log. */
47	export interface TaskLogEntry {
48	  action: string;
49	  by: string;
50	  at: string;
51	  note?: string;
52	  [key: string]: unknown;
53	}
54	
55	/** Execution metadata stored on the task. */
56	export interface TaskExecution {
57	  actor_type: ActorType;
58	  last_updated_by: string | null;
59	  last_updated_at: string | null;
60	  /** Written by the agent when blocking; a short human-readable triage hint. */
61	  suggested_next_step?: string | null;
62	}
63	
64	/** Pull-request reference stored on the task. */
65	export interface TaskPr {
66	  url: string;
67	  status: PrStatus;
68	}
69	
70	/**
71	 * Written by the orchestrator (or agent) when a task transitions to `blocked`.
72	 * Captures the exact WIP state so a recovery agent can resume from the same
73	 * branch and SHA rather than starting from scratch.
74	 */
75	export interface BlockedContext {
76	  /** Branch name carrying the WIP commits (e.g. `feature/my-feature-T3`). */
77	  wip_branch: string;
78	  /** HEAD SHA at the time the block was recorded. */
79	  wip_sha: string;
80	  /** ISO-8601 timestamp with timezone when the branch was last pushed. */
81	  pushed_at: string;
82	}
83	
84	/** Full task state as stored in tasks/T<n>.yaml. */
85	export interface Task {
86	  id: string;
87	  title: string;
88	  repo: string;
89	  status: TaskStatus;
90	  depends_on: string[];
91	  blocked_reason: BlockedReason | null;
92	  /** Structured context for blocked_reason (e.g. current_model for escalation). */
93	  blocked_details?: string | Record<string, unknown> | null;
94	  /**
95	   * WIP branch/SHA snapshot written when the task is blocked.
96	   * Null when the task has never been blocked, or after a successful completion.
97	   */
98	  blocked_context: BlockedContext | null;
99	  branch: string;
100	  execution: TaskExecution;
101	  /** Implementation-repo PR (opened by the agent after work is complete). */
102	  pr: TaskPr;
103	  /**
104	   * Management-repo PR opened at claim time (feature branch → main).
105	   * Null until the claim commit is pushed and the PR is created.
106	   */
107	  workspace_pr: TaskPr | null;
108	  log: TaskLogEntry[];
109	  /**
110	   * Tracks mergeability of the implementation PR.
111	   * Set by the polling loop when a conflict is detected and updated by the
112	   * rebase handler as it progresses.  Omitted / null until the feature's PR
113	   * has been opened.
114	   */
115	  conflict_state?: ConflictState | null;
116	  /**
117	   * Append-only log of rebase operations performed against this task's
118	   * implementation branch.  Each entry is written atomically with the
119	   * associated management-repo push so the log is always consistent with the
120	   * branch state.
121	   */
122	  rebase_log?: RebaseLogEntry[];
123	}
124

