/** Task lifecycle statuses. */
export type TaskStatus =
  | "todo"
  | "ready"
  | "in_progress"
  | "blocked"
  | "in_review"
  | "done"
  | "cancelled";

/** Reasons a task may be blocked. Written to task.yaml when status becomes blocked. */
export type BlockedReason =
  | "budget_exceeded"
  | "iteration_cap_exceeded"
  | "no_progress"
  | "model_escalation_requested"
  | "skill_missing"
  | "runtime_error"
  | "pr_conflict";

/** Who may execute a task. */
export type ActorType = "human" | "agent" | "either";

/**
 * Tracks the mergeability lifecycle of a task's implementation PR.
 * Written to `conflict_state` on the task YAML when the polling loop detects
 * a conflict or when the rebase handler updates resolution progress.
 */
export type ConflictState = "none" | "conflicted" | "resolving" | "resolved";

/** One entry in the append-only rebase audit log stored on the task. */
export interface RebaseLogEntry {
  /** ISO-8601 timestamp when this entry was written. */
  at: string;
  /** What the rebase handler did or observed at this point. */
  action: "rebase_started" | "rebase_completed" | "rebase_blocked" | "rebase_resolved_by_agent";
  /** Agent email or actor identifier that wrote this entry. */
  by: string;
  /** Human-readable detail — e.g. file:line pointers for conflicted hunks. */
  note?: string;
}

/** Pull-request lifecycle state. */
export type PrStatus = "not_created" | "open" | "merged" | "closed";

/** One entry in the task's append-only audit log. */
export interface TaskLogEntry {
  action: string;
  by: string;
  at: string;
  note?: string;
  [key: string]: unknown;
}

/** Execution metadata stored on the task. */
export interface TaskExecution {
  actor_type: ActorType;
  last_updated_by: string | null;
  last_updated_at: string | null;
  /** Written by the agent when blocking; a short human-readable triage hint. */
  suggested_next_step?: string | null;
}

/** Pull-request reference stored on the task. */
export interface TaskPr {
  url: string;
  status: PrStatus;
}

/**
 * Written by the orchestrator (or agent) when a task transitions to `blocked`.
 * Captures the exact WIP state so a recovery agent can resume from the same
 * branch and SHA rather than starting from scratch.
 */
export interface BlockedContext {
  /** Branch name carrying the WIP commits (e.g. `feature/my-feature-T3`). */
  wip_branch: string;
  /** HEAD SHA at the time the block was recorded. */
  wip_sha: string;
  /** ISO-8601 timestamp with timezone when the branch was last pushed. */
  pushed_at: string;
}

/** Full task state as stored in tasks/T<n>.yaml. */
export interface Task {
  id: string;
  title: string;
  repo: string;
  status: TaskStatus;
  depends_on: string[];
  blocked_reason: BlockedReason | null;
  /** Structured context for blocked_reason (e.g. current_model for escalation). */
  blocked_details?: string | Record<string, unknown> | null;
  /**
   * WIP branch/SHA snapshot written when the task is blocked.
   * Null when the task has never been blocked, or after a successful completion.
   */
  blocked_context: BlockedContext | null;
  branch: string;
  execution: TaskExecution;
  /** Implementation-repo PR (opened by the agent after work is complete). */
  pr: TaskPr;
  /**
   * Management-repo PR opened at claim time (feature branch → main).
   * Null until the claim commit is pushed and the PR is created.
   */
  workspace_pr: TaskPr | null;
  log: TaskLogEntry[];
  /**
   * Tracks mergeability of the implementation PR.
   * Set by the polling loop when a conflict is detected and updated by the
   * rebase handler as it progresses.  Omitted / null until the feature's PR
   * has been opened.
   */
  conflict_state?: ConflictState | null;
  /**
   * Append-only log of rebase operations performed against this task's
   * implementation branch.  Each entry is written atomically with the
   * associated management-repo push so the log is always consistent with the
   * branch state.
   */
  rebase_log?: RebaseLogEntry[];
}

