1	/**
2	 * Canonical path constants and builder helpers for the workspace artifact layout.
3	 *
4	 * Every workflow-specific file name, directory segment, and path composition
5	 * MUST be defined here. No source file may hardcode these strings inline.
6	 *
7	 * Workspace layout:
8	 *   <workspaceRoot>/
9	 *     workspace.yaml
10	 *     docs/features/<featureId>/
11	 *       tasks.md
12	 *       tasks/<taskId>.yaml
13	 *       logs/<taskId>/<iso>.jsonl
14	 *
15	 * Workflow repo layout:
16	 *   <workflowRoot>/
17	 *     technical_skills/<slug>/
18	 *       SKILL.md
19	 */
20	
21	import { join } from "node:path";
22	
23	// ── Segment constants ─────────────────────────────────────────────────────────
24	
25	/** Root config file in every management workspace. */
26	export const WORKSPACE_YAML = "workspace.yaml";
27	
28	/** Narrative task index file at the feature level. */
29	export const TASKS_MD = "tasks.md";
30	
31	/** Sub-directory holding per-task YAML state files. */
32	export const TASKS_DIR = "tasks";
33	
34	/** Sub-directory holding per-run JSONL log files. */
35	export const LOGS_DIR = "logs";
36	
37	/** Directory under the workflow repo holding technical skill definitions. */
38	export const TECHNICAL_SKILLS_DIR = "technical_skills";
39	
40	/** Skill definition file inside each technical skill directory. */
41	export const SKILL_MD = "SKILL.md";
42	
43	// ── Path builder helpers ──────────────────────────────────────────────────────
44	
45	/** `<workspaceRoot>/workspace.yaml` */
46	export function workspaceYamlPath(workspaceRoot: string): string {
47	  return join(workspaceRoot, WORKSPACE_YAML);
48	}
49	
50	/** `<workspaceRoot>/docs/features/` */
51	export function featuresRoot(workspaceRoot: string): string {
52	  return join(workspaceRoot, "docs", "features");
53	}
54	
55	/** `<workspaceRoot>/docs/features/<featureId>/tasks/<taskId>.yaml` */
56	export function taskYamlAbsPath(
57	  workspaceRoot: string,
58	  featureId: string,
59	  taskId: string,
60	): string {
61	  return join(workspaceRoot, "docs", "features", featureId, TASKS_DIR, `${taskId}.yaml`);
62	}
63	
64	/** Relative path for git operations: `docs/features/<featureId>/tasks/<taskId>.yaml` */
65	export function taskYamlRelPath(featureId: string, taskId: string): string {
66	  return join("docs", "features", featureId, TASKS_DIR, `${taskId}.yaml`);
67	}
68	
69	/** `<workspaceRoot>/docs/features/<featureId>/tasks.md` */
70	export function tasksMdAbsPath(workspaceRoot: string, featureId: string): string {
71	  return join(workspaceRoot, "docs", "features", featureId, TASKS_MD);
72	}
73	
74	/** `<workspaceRoot>/docs/features/<featureId>/logs/<taskId>/` */
