1	/**
2	 * Agent-runtime main entry point.
3	 *
4	 * Lifecycle:
5	 *   bootstrap (once) → polling loop:
6	 *     pull workspaces → eligibility → claim → run-claude → sleep → repeat
7	 *
8	 * idle_sleep_seconds controls the loop behaviour (read from agent.yaml):
9	 *   0   → single-shot mode: one cycle then exit (for external schedulers)
10	 *   >0  → continuous: loops indefinitely, sleeping idle_sleep_seconds between cycles
11	 *
12	 * Exit codes:
13	 *   0  normal exit (task ran, idle cycle, or kill-switch off)
14	 *   2  agent.yaml invalid
15	 *   3  git clone/pull failed (bootstrap only — per-cycle pull failures never exit)
16	 *   4  unexpected fatal error
17	 */
18	
19	import { existsSync, readFileSync } from "node:fs";
20	import { join } from "node:path";
21	import { parse as parseYaml } from "yaml";
22	import { runBootstrap } from "./bootstrap/bootstrap.js";
23	import { resolveSSHKey } from "./resolve-ssh-key.js";
24	import { workspaceYamlPath, taskYamlAbsPath, taskBranchName } from "./paths.js";
25	import { findEligibleTasks } from "./eligibility/match.js";
26	import { claimTask } from "./claim/claim-task.js";
27	import { openWorkspacePr, parseGitHubCoords } from "./claim/open-workspace-pr.js";
28	import type { Task } from "./types/task.js";
29	import { generateAgentContext } from "./bootstrap/agent-context.js";
30	import { fetchRagContext } from "./bootstrap/fetch-rag-context.js";
31	import { runClaude } from "./loop/run-claude.js";
32	import { resolveModel } from "./config/resolve-model-policy.js";
33	import { parseModelOverrides } from "./config/parse-model-overrides.js";
34	import type { ModelPolicy } from "./config/resolve-model-policy.js";
35	import { pullWorkspaces } from "./poll/pull-workspaces.js";
36	import { runAgentLoop, type CycleOutcome } from "./poll/agent-loop.js";
37	import { checkInReviewPrs } from "./poll/check-in-review-prs.js";
38	import { handleMergeConflicts } from "./pr-response/auto-rebase.js";
39	import { handleDraftReviews } from "./pr-response/dispatch-draft-review.js";
40	
41	// ── Helpers ───────────────────────────────────────────────────────────────────
42	
43	function requireEnv(name: string): string {
44	  const val = process.env[name];
45	  if (!val) throw new Error(`Required environment variable ${name} is not set`);
46	  return val;
47	}
48	
49	/** Extract repo name from SSH or HTTPS URL (strips .git suffix). */
50	function extractRepoName(url: string): string {
51	  const match = /\/([^/]+?)(?:\.git)?$/.exec(url);
52	  return match?.[1] ?? url;
53	}
54	
55	/** Emit a structured JSON event to stdout. */
56	function emit(event: Record<string, unknown>): void {
57	  console.log(JSON.stringify({ at: new Date().toISOString(), ...event }));
58	}
59	
60	/**
61	 * Given a task's repo ID and the workspace.yaml from the management workspace,
62	 * resolve the local filesystem path where that repo is cloned.
63	 *
64	 * Bootstrap (step 5b) guarantees that process.env[VAR] is set for every
65	 * local_path: env:<VAR> declaration before main() reaches this call.
66	 */
67	function resolveRepoLocalPath(
68	  workspaceRoot: string,
69	  repoId: string,
70	): string {
71	  type RepoEntry = { id: string; github: string; local_path?: string };
72	  const yaml = parseYaml(
73	    readFileSync(workspaceYamlPath(workspaceRoot), "utf-8"),
74	  ) as { repos: RepoEntry[] };
75	
76	  const repo = yaml.repos.find((r) => r.id === repoId);
77	  if (!repo) throw new Error(`Repo "${repoId}" not found in workspace.yaml`);
78	
79	  if (!repo.local_path?.startsWith("env:")) {
80	    throw new Error(
81	      `Repo "${repoId}" has no "local_path: env:<VAR>" declaration in workspace.yaml. ` +
82	      `Bootstrap is responsible for setting the env var before this point.`,
83	    );
84	  }
85	
86	  const envVar = repo.local_path.slice(4);
87	  const val = process.env[envVar];
88	  if (!val) {
89	    throw new Error(
90	      `Env var ${envVar} is not set — bootstrap should have populated it for repo "${repoId}".`,
91	    );
92	  }
93	  return val;
94	}
95	
96	/**
97	 * Resolve the base branch for a repo ID from workspace.yaml.
98	 * Defaults to "main" if not declared.
99	 */
100	function resolveRepoBaseBranch(
101	  workspaceRoot: string,
102	  repoId: string,
103	): string {
104	  type RepoEntry = { id: string; base_branch?: string };
105	  const yaml = parseYaml(
106	    readFileSync(workspaceYamlPath(workspaceRoot), "utf-8"),
107	  ) as { repos: RepoEntry[] };
108	
109	  const repo = yaml.repos.find((r) => r.id === repoId);
110	  if (!repo) throw new Error(`Repo "${repoId}" not found in workspace.yaml`);
111	  return repo.base_branch ?? "main";
112	}
113	
114	/**
115	 * Read the task YAML for a given feature/task and return its repo field.
116	 */
117	function resolveTaskRepoId(
118	  workspaceRoot: string,
119	  featureId: string,
120	  taskId: string,
121	): string {
122	  const task = parseYaml(
123	    readFileSync(taskYamlAbsPath(workspaceRoot, featureId, taskId), "utf-8"),
124	  ) as { repo: string };
125	  if (!task.repo) throw new Error(`Task ${taskId} has no repo field`);
126	  return task.repo;
127	}
128	
129	/**
130	 * Load the workspace-level model_policy from workspace.yaml.
131	 * Returns a minimal fallback policy if the field is absent (e.g. older workspaces).
132	 */
133	function loadWorkspaceModelPolicy(workspaceRoot: string): ModelPolicy {
134	  const yaml = parseYaml(
135	    readFileSync(workspaceYamlPath(workspaceRoot), "utf-8"),
136	  ) as { model_policy?: ModelPolicy };
137	
138	  if (yaml.model_policy) return yaml.model_policy;
139	
140	  // Sensible fallback so the runtime never hard-errors on a missing policy.
141	  const defaultPhase = {
142	    allowed: ["claude-sonnet-4-6"],
143	    default: "claude-sonnet-4-6",
144	  };
145	  return {
146	    implementation: defaultPhase,
147	    self_review: defaultPhase,
148	    pr_description: defaultPhase,
149	    suggested_next_step: { allowed: ["claude-haiku-4-5-20251001"], default: "claude-haiku-4-5-20251001" },
150	  };
151	}
152	
153	
154	/**
155	 * Parse the GitHub owner/repo and base branch for the management repo declared
156	 * in workspace.yaml. Used to call openWorkspacePr after a successful claim.
157	 */
158	function parseManagementRepoCoords(
159	  workspaceRoot: string,
160	): { owner: string; repo: string; baseBranch: string } {
161	  type RepoEntry = { id: string; github: string; local_path?: string; base_branch?: string };
162	  const yaml = parseYaml(
163	    readFileSync(workspaceYamlPath(workspaceRoot), "utf-8"),
164	  ) as { management_repo: string; repos: RepoEntry[] };
165	
166	  const mgmtId = yaml.management_repo;
167	  const mgmtRepo = yaml.repos.find((r) => r.id === mgmtId);
168	  if (!mgmtRepo) {
169	    throw new Error(`Management repo "${mgmtId}" not found in workspace.yaml repos`);
170	  }
171	  const { owner, repo } = parseGitHubCoords(mgmtRepo.github);
172	  return { owner, repo, baseBranch: mgmtRepo.base_branch ?? "main" };
173	}
174	
175	// ── Main ──────────────────────────────────────────────────────────────────────
176	
177	async function main(): Promise<number> {
178	  // ── 1. Read required environment ─────────────────────────────────────────
179	  let agentYamlPath: string;
180	  let workflowLocalPath: string;
181	  let workspacesRoot: string;
182	  let gitAuthorEmail: string;
183	
184	  try {
185	    agentYamlPath = requireEnv("AGENT_YAML_PATH");
186	    workflowLocalPath = requireEnv("WORKFLOW_LOCAL_PATH");
187	    workspacesRoot = requireEnv("WORKSPACES_ROOT");
188	    gitAuthorEmail = requireEnv("GIT_AUTHOR_EMAIL");
189	  } catch (e) {
190	    emit({ type: "fatal_missing_env", details: (e as Error).message });
191	    return 4;
192	  }
193	
194	  const gitAuthorName = process.env.GIT_AUTHOR_NAME ?? gitAuthorEmail;
195	
196	  // ── SSH key resolution ────────────────────────────────────────────────────
197	  // Preferred: SSH_PRIVATE_KEY env var (raw PEM) — write to temp file 0400.
198	  // Fallback:  SSH_KEY_PATH env var pointing to a file already present.
199	  // Neither:   warn and proceed; SSH-only repos will fail at clone time.
200	  const sshResolution = resolveSSHKey(process.env);
201	  const sshKeyPath = sshResolution.sshKeyPath;
202	  if (sshResolution.warned) {
203	    emit({ type: "warn_no_ssh_key", note: "Neither SSH_PRIVATE_KEY nor SSH_KEY_PATH is set. SSH-only git operations will fail." });
204	  }
205	
206	  // ── 2. Bootstrap (once at container start) ────────────────────────────────
207	  const bootstrapResult = await runBootstrap({
208	    agentYamlPath,
209	    workflowLocalPath,
210	    workflowUrl: process.env.WORKFLOW_URL,
211	    workspacesRoot,
212	    sshKeyPath,
213	  });
214	
215	  if (bootstrapResult.exitCode !== 0) return bootstrapResult.exitCode;
216	
217	  const config = bootstrapResult.config!;
218	
219	  // Kill switch already handled inside runBootstrap (exits 0).
220	  // If we get here, config.enabled is true.
221	
222	  // ── 3. Build the per-cycle scan+claim+run function ────────────────────────
223	  const githubToken = process.env.GITHUB_TOKEN ?? "";
224	  if (!githubToken) {
225	    emit({ type: "warn_no_github_token" });
226	  }
227	
228	  // Tracks the last time the in_review PR poll ran (ms since epoch, or null).
229	  let lastPrPollAt: number | null = null;
230	
231	  async function runOneCycle(): Promise<CycleOutcome> {
232	    // ── 3a. Pull latest workspace state ──────────────────────────────────────
233	    const pullResults = pullWorkspaces({
234	      watchUrls: config.watches,
235	      sshKeyPath,
236	      workspacesRoot,
237	      workflowUrl: process.env.WORKFLOW_URL,
238	      workflowLocalPath,
239	      emit,
240	    });
241	
242	    // Build a set of workspaces that failed to pull — skip scanning them.
243	    const haltedUrls = new Set(
244	      pullResults
245	        .filter((r) => r.outcome === "halt" || r.outcome === "warn")
246	        .map((r) => r.url),
247	    );
248	
249	    // ── 3b. Scan remaining workspaces for an eligible task ────────────────────
250	    // Track outcome separately so the in_review pass always runs after.
251	    let outcome: CycleOutcome = "idle";
252	
253	    // Collect workspace paths that were pulled successfully (for in_review poll).
254	    const pulledWorkspaceRoots: string[] = [];
255	
256	    outerLoop:
257	    for (const watchUrl of config.watches) {
258	      if (haltedUrls.has(watchUrl)) continue;
259	
260	      const workspaceLocalPath = join(workspacesRoot, extractRepoName(watchUrl));
261	      pulledWorkspaceRoots.push(workspaceLocalPath);
262	
263	      if (!existsSync(workspaceLocalPath)) {
264	        emit({ type: "workspace_not_found", workspace_url: watchUrl, local_path: workspaceLocalPath });
265	        continue;
266	      }
267	
268	      // Find eligible tasks in this workspace.
269	      let eligibleTasks;
270	      try {
271	        eligibleTasks = findEligibleTasks(config, workspaceLocalPath, workflowLocalPath);
272	      } catch (e) {
273	        emit({ type: "eligibility_error", workspace_url: watchUrl, details: String(e) });
274	        continue;
275	      }
276	
277	      if (eligibleTasks.length === 0) {
278	        emit({ type: "no_eligible_tasks", workspace_url: watchUrl });
279	        continue;
280	      }
281	
282	      // Try each task in order until one is claimed.
283	      for (const { task, featureId } of eligibleTasks) {
284	        // ── Claim ─────────────────────────────────────────────────────────────
285	        const claimResult = await claimTask({
286	          workspaceRoot: workspaceLocalPath,
287	          taskId: task.id,
288	          featureId,
289	          gitAuthorEmail,
290	          gitAuthorName,
291	          sshKeyPath,
292	          jitterMaxSeconds: config.jitter_max_seconds,
293	        });
294	
295	        const taskBranch = taskBranchName(featureId, task.id);
296	
297	        if (!claimResult.won) {
298	          if (claimResult.reason !== "branch_blocked_recovery") {
299	            emit({ type: "claim_lost", task_id: task.id, feature_id: featureId, reason: claimResult.reason });
300	            continue;
301	          }
302	          emit({ type: "task_blocked_recovery_detected", task_id: task.id, feature_id: featureId });
303	          const _recoveredTask = parseYaml(
304	            readFileSync(taskYamlAbsPath(workspaceLocalPath, featureId, task.id), "utf-8"),
305	          ) as Task;
306	          void _recoveredTask;
307	        } else {
308	          emit({ type: "task_claimed", task_id: task.id, feature_id: featureId });
309	        }
310	
311	        // ── Open management-repo PR (non-fatal) ───────────────────────────────
312	        if (githubToken) {
313	          try {
314	            const mgmtCoords = parseManagementRepoCoords(workspaceLocalPath);
315	            await openWorkspacePr({
316	              workspaceRoot: workspaceLocalPath,
317	              featureId,
318	              taskId: task.id,
319	              branch: taskBranch,
320	              baseBranch: mgmtCoords.baseBranch,
321	              githubToken,
322	              repoOwner: mgmtCoords.owner,
323	              repoName: mgmtCoords.repo,
324	              gitAuthorEmail,
325	              gitAuthorName,
326	              sshKeyPath,
327	            });
328	            emit({ type: "workspace_pr_opened", task_id: task.id, feature_id: featureId });
329	          } catch (e) {
330	            emit({ type: "workspace_pr_failed", task_id: task.id, feature_id: featureId, details: String(e) });
331	          }
332	        }
333	
334	        // ── Load model policy + resolve task repo path ────────────────────────
335	        const workspaceModelPolicy = loadWorkspaceModelPolicy(workspaceLocalPath);
336	        const taskRepoRoot = resolveRepoLocalPath(workspaceLocalPath, task.repo);
337	
338	        // ── Resolve implementation model + parse task-level overrides ─────────
339	        const tasksMdPath = join(workspaceLocalPath, "docs", "features", featureId, "tasks.md");
340	        let taskModelOverrides = {};
341	        try {
342	          const tasksMdContent = readFileSync(tasksMdPath, "utf-8");
343	          taskModelOverrides = parseModelOverrides(tasksMdContent, task.id);
344	        } catch {
345	          // Non-fatal — use workspace defaults if tasks.md is unreadable.
346	        }
347	        const implementationModel = resolveModel(
348	          workspaceModelPolicy,
349	          taskModelOverrides,
350	          "implementation",
351	          task.id,
352	        );
353	
354	        // ── Generate agent context ─────────────────────────────────────────────
355	        const baseAgentContext = generateAgentContext({
356	          taskId: task.id,
357	          featureId,
358	          taskTitle: task.title,
359	          taskBranch,
360	          taskRepo: task.repo,
361	          taskRepoRoot,
362	          workspaceRoot: workspaceLocalPath,
363	          gitAuthorEmail,
364	          gitAuthorName,
365	          implementationModel,
366	        });
367	
368	        // ── Pre-inject RAG context ─────────────────────────────────────────────
369	        const mcpRagUrl = process.env.MCP_RAG_URL;
370	        const workspaceYaml = parseYaml(
371	          readFileSync(workspaceYamlPath(workspaceLocalPath), "utf-8"),
372	        ) as { workspace_id: string };
373	        const ragBlock = mcpRagUrl
374	          ? await fetchRagContext(mcpRagUrl, `${task.title} ${featureId}`, workspaceYaml.workspace_id)
375	          : "";
376	        const agentContext = ragBlock ? `${baseAgentContext}\n\n${ragBlock}` : baseAgentContext;
377	
378	        // ── Run claude ─────────────────────────────────────────────────────────
379	        const runResult = await runClaude({
380	          taskId: task.id,
381	          featureId,
382	          workspaceRoot: workspaceLocalPath,
383	          taskRepoRoot,
384	          workflowLocalPath,
385	          agentContext,
386	          maxTurns: config.budget.max_iterations,
387	          maxTokens: config.budget.max_tokens_per_task,
388	          sshKeyPath,
389	          gitAuthorEmail,
390	          taskBranch,
391	          logSinkEnabled: config.log_sink.enabled,
392	        });
393	
394	        emit({ type: "task_run_complete", task_id: task.id, feature_id: featureId, outcome: runResult.outcome });
395	        outcome = "ran_task";
396	        // Break out of both loops — but still complete the in_review pass below.
397	        break outerLoop;
398	      }
399	    }
400	
401	    // ── 3c. In-review PR poll ─────────────────────────────────────────────────
402	    // Runs after every ready-task pass, regardless of whether a task was claimed.
403	    // Skipped if it ran within pr_poll_interval_seconds.
404	    if (githubToken) {
405	      const prPollIntervalMs =
406	        (config.pr_poll_interval_seconds ?? config.idle_sleep_seconds ?? 60) * 1000;
407	      const now = Date.now();
408	
409	      if (lastPrPollAt === null || now - lastPrPollAt >= prPollIntervalMs) {
410	        if (pulledWorkspaceRoots.length > 0) lastPrPollAt = now;
411	        try {
412	          const prResults = await checkInReviewPrs({
413	            workspaceRoots: pulledWorkspaceRoots,
414	            githubToken,
415	            emit,
416	          });
417	
418	          // ── T3: Auto-rebase for mergeable === false tasks ──────────────────────
419	          // Run per workspace so the resolver closures have the correct root.
420	          for (const wsRoot of pulledWorkspaceRoots) {
421	            const wsResults = prResults.filter((r) => r.workspaceRoot === wsRoot);
422	            if (wsResults.some((r) => r.mergeable === false)) {
423	              await handleMergeConflicts({
424	                prResults: wsResults,
425	                workspaceRoot: wsRoot,
426	                resolveImplRepoRoot: (repoId) =>
427	                  resolveRepoLocalPath(wsRoot, repoId),
428	                resolveImplBaseBranch: (repoId) =>
429	                  resolveRepoBaseBranch(wsRoot, repoId),
430	                resolveTaskRepoId: (featureId, taskId) =>
431	                  resolveTaskRepoId(wsRoot, featureId, taskId),
432	                gitAuthorEmail,
433	                gitAuthorName,
434	                sshKeyPath,
435	                emit,
436	              });
437	            }
438	          }
439	
440	          // ── T4: Review dispatch for tasks with open comments ──────────────────
441	          // Run per workspace so the resolver closures have the correct root.
442	          for (const wsRoot of pulledWorkspaceRoots) {
443	            const wsResults = prResults.filter((r) => r.workspaceRoot === wsRoot);
444	            if (wsResults.some((r) => r.hasOpenComments === true)) {
445	              const wsModelPolicy = loadWorkspaceModelPolicy(wsRoot);
446	              await handleDraftReviews({
447	                prResults: wsResults,
448	                workspaceRoot: wsRoot,
449	                resolveImplRepoRoot: (repoId) =>
450	                  resolveRepoLocalPath(wsRoot, repoId),
451	                resolveTaskRepoId: (featureId, taskId) =>
452	                  resolveTaskRepoId(wsRoot, featureId, taskId),
453	                resolveImplementationModel: (featureId, taskId) => {
454	                  try {
455	                    const tasksMdPath = join(wsRoot, "docs", "features", featureId, "tasks.md");
456	                    const content = readFileSync(tasksMdPath, "utf-8");
457	                    const overrides = parseModelOverrides(content, taskId);
458	                    return resolveModel(wsModelPolicy, overrides, "implementation", taskId);
459	                  } catch {
460	                    return resolveModel(wsModelPolicy, {}, "implementation", taskId);
461	                  }
462	                },
463	                gitAuthorEmail,
464	                gitAuthorName,
465	                sshKeyPath,
466	                workflowLocalPath,
467	                maxTurns: config.budget.max_iterations,
468	                maxTokens: config.budget.max_tokens_per_task,
469	                logSinkEnabled: config.log_sink.enabled,
470	                emit,
471	              });
472	            }
473	          }
474	        } catch (e) {
475	          emit({ type: "in_review_poll_error", details: String(e) });
476	        }
477	      }
478	    }
479	
480	    return outcome;
481	  }
482	
483	  // ── 4. Run the polling loop ───────────────────────────────────────────────
484	  await runAgentLoop({ config, runCycle: runOneCycle, emit });
485	
486	  return 0;
487	}
488	
489	main()
490	  .then((code) => process.exit(code))
491	  .catch((e) => {
492	    try {
493	      console.log(
494	        JSON.stringify({
495	          type: "fatal_error",
496	          details: (e as Error).message ?? String(e),
497	          at: new Date().toISOString(),
498	        }),
499	      );
500	    } catch {
501	      /* cannot emit — last resort */
502	    }
503	    process.exit(4);
504	  });
