1	/**
2	 * T3: Auto-rebase handler.
3	 *
4	 * When the in_review poll (T2) reports `mergeable: false` for a task, this
5	 * handler:
6	 *
7	 *   1. Claims the rebase work via a first-push-wins mechanism: appends a
8	 *      `rebase_started` log entry to the task YAML on the management-repo
9	 *      feature branch and pushes. If the push is rejected, another agent
10	 *      claimed first — skip this cycle (`rebase_claim_lost`).
11	 *
12	 *   2. In the implementation repo: `git fetch origin` then
13	 *      `git rebase origin/<base_branch>`.
14	 *
15	 *   3. Clean rebase (exit 0):
16	 *        - `git push --force-with-lease` the impl branch.
17	 *        - Update task YAML: `conflict_state: resolved`, append
18	 *          `rebase_completed` log entry.
19	 *        - Push the management repo feature branch.
20	 *        - Emit `rebase_completed`.
21	 *
22	 *   4. Conflicted rebase (exit ≠ 0) — three-tier logic:
23	 *
24	 *      a. If ALL conflicted files are in files the agent authored on this
25	 *         branch (`git diff --name-only origin/<base>...HEAD`):
26	 *           - Emit `rebase_resolve_attempt`.
27	 *           - Spawn Claude to resolve the conflict markers in each file.
28	 *           - Run `git add -A` then `git rebase --continue`.
29	 *           - If continue succeeds: treat as a clean rebase (force-push,
30	 *             mark resolved). Emit `rebase_resolved_by_agent`.
31	 *           - If Claude fails or continue fails: emit `rebase_resolve_failed`
32	 *             and fall through to block path.
33	 *
34	 *      b. If ANY conflicted file was NOT authored by the agent:
35	 *           - Block immediately (human-owned files must not be auto-modified).
36	 *
37	 *      c. Block path:
38	 *           - Stage all conflict markers (`git add -A`).
39	 *           - Commit with a descriptive message.
40	 *           - Push the impl branch.
41	 *           - Update task YAML: `status: blocked`,
42	 *             `blocked_reason: pr_conflict`, `conflict_state: conflicted`,
43	 *             append `rebase_blocked` log entry with file:line pointers.
44	 *           - Push the management repo feature branch.
45	 *           - Emit `rebase_blocked`.
46	 */
47	
48	import { execSync, spawnSync, spawn } from "node:child_process";
49	import { readFileSync, writeFileSync } from "node:fs";
50	import { parse as parseYaml, stringify as yamlStringify } from "yaml";
51	import type { Task, RebaseLogEntry } from "../types/task.js";
52	import { taskYamlAbsPath, taskYamlRelPath } from "../paths.js";
53	import type { PrStatusResult } from "../poll/check-in-review-prs.js";
54	import { buildGitCommitEnv } from "../git-env.js";
55	
56	// ── Public types ──────────────────────────────────────────────────────────────
57	
58	export interface AutoRebaseOptions {
59	  /** Absolute path to the management (workspace) repo root. */
60	  workspaceRoot: string;
61	  /** Feature directory ID (e.g. "agent-pr-response"). */
62	  featureId: string;
63	  /** Task ID (e.g. "T3"). */
64	  taskId: string;
65	  /** Task feature branch name (e.g. "feature/agent-pr-response-T3"). */
66	  taskBranch: string;
67	  /** Absolute path to the implementation repo root. */
68	  implRepoRoot: string;
69	  /**
70	   * Base branch of the implementation repo (e.g. "main").
71	   * The rebase targets `origin/<implBaseBranch>`.
72	   */
73	  implBaseBranch: string;
74	  /** GIT_AUTHOR_EMAIL for commits and log entries. */
75	  gitAuthorEmail: string;
76	  /** GIT_AUTHOR_NAME for commits. Defaults to gitAuthorEmail. */
77	  gitAuthorName?: string;
78	  /** SSH private key path for git push operations. */
79	  sshKeyPath?: string;
80	  /** Structured event emitter for observability. */
81	  emit: (event: Record<string, unknown>) => void;
82	  /**
83	   * Optional override for spawning Claude to resolve conflicts.
84	   * Receives the prompt string, the impl repo cwd, and the process env.
85	   * Returns true if resolution succeeded, false otherwise.
86	   * Defaults to `defaultInvokeClaudeForResolution`.
87	   */
88	  invokeClaudeForResolution?: (
89	    prompt: string,
90	    cwd: string,
91	    env: NodeJS.ProcessEnv,
92	  ) => Promise<boolean>;
93	}
94	
95	export type AutoRebaseOutcome =
96	  | "claim_lost"        // Another agent already claimed the rebase.
97	  | "rebase_completed"  // Rebase was clean; impl branch force-pushed.
98	  | "rebase_blocked";   // Conflicts remain; task set to blocked.
