125	/**
126	 * Commit and push the updated task YAML to the management repo task branch.
127	 * Non-fatal: logs errors via emit but does not throw.
128	 */
129	function commitAndPushTaskYaml(
130	  workspaceRoot: string,
131	  featureId: string,
132	  taskId: string,
133	  taskBranch: string,
134	  commitMessage: string,
135	  env: NodeJS.ProcessEnv,
136	): void {
137	  const relPath = taskYamlRelPath(featureId, taskId);
138	  execSync(`git -C "${workspaceRoot}" add "${relPath}"`, {
139	    env,
140	    stdio: "pipe",
141	  });
142	  execSync(
143	    `git -C "${workspaceRoot}" commit -m "${commitMessage}"`,
144	    { env, stdio: "pipe" },
145	  );
146	  execSync(
147	    `git -C "${workspaceRoot}" push origin "${taskBranch}"`,
148	    { env, stdio: "pipe" },
149	  );
150	}
