152	/**
153	 * Return all files that currently have conflict markers via `git diff --name-only`.
154	 * Falls back to an empty array on error.
155	 */
156	function listConflictedFiles(
157	  implRepoRoot: string,
158	  env: NodeJS.ProcessEnv,
159	): string[] {
160	  try {
161	    const output = execSync(
162	      `git -C "${implRepoRoot}" diff --name-only --diff-filter=U`,
163	      { env, encoding: "utf-8", stdio: ["ignore", "pipe", "pipe"] },
164	    ).trim();
165	    return output ? output.split("\n") : [];
166	  } catch {
167	    return [];
168	  }
169	}
170	
171	/**
172	 * Return the set of files the agent has touched on this branch relative to
173	 * origin/<baseBranch>. Uses `git diff --name-only origin/<base>...HEAD`.
174	 * Falls back to an empty Set on error.
175	 */
176	function listAgentAuthoredFiles(
177	  implRepoRoot: string,
178	  baseBranch: string,
179	  env: NodeJS.ProcessEnv,
180	): Set<string> {
181	  try {
182	    const output = execSync(
183	      `git -C "${implRepoRoot}" diff --name-only origin/${baseBranch}...HEAD`,
184	      { env, encoding: "utf-8", stdio: ["ignore", "pipe", "pipe"] },
185	    ).trim();
186	    return new Set(output ? output.split("\n") : []);
187	  } catch {
188	    return new Set();
189	  }
190	}
