192	/**
193	 * Build the prompt to send to Claude for resolving conflict markers.
194	 * For dependency manifest files, instruct a union merge.
195	 * For other files, instruct preservation of all functionality from both sides.
196	 */
197	function buildConflictResolutionPrompt(
198	  implRepoRoot: string,
199	  baseBranch: string,
200	  conflictedFiles: string[],
201	): string {
202	  const depFiles = new Set([
203	    "pyproject.toml",
204	    "requirements.txt",
205	    "package.json",
206	    "go.mod",
207	    "Cargo.toml",
208	  ]);
209	
210	  const fileInstructions = conflictedFiles
211	    .map((f) => {
212	      const basename = f.split("/").pop() ?? f;
213	      if (depFiles.has(basename)) {
214	        return `- ${f}: dependency manifest — take the UNION of both sides (include all packages/versions from both HEAD and ${baseBranch}, keeping the higher version where there are conflicts)`;
215	      }
216	      return `- ${f}: preserve ALL functionality from both sides; do not drop any code`;
217	    })
218	    .join("\n");
219	
220	  return (
221	    `You are resolving git merge conflicts after a rebase in the repository at ${implRepoRoot}.\n` +
222	    `The following files contain conflict markers (<<<<<<<, =======, >>>>>>>):\n\n` +
223	    fileInstructions +
224	    `\n\nFor each file:\n` +
225	    `1. Read the file contents (which include conflict markers).\n` +
226	    `2. Resolve the conflict markers according to the instructions above.\n` +
227	    `3. Write the fully resolved content back to disk.\n\n` +
228	    `IMPORTANT:\n` +
229	    `- Do NOT run git add or git commit — only write the resolved file contents.\n` +
230	    `- Do NOT modify any files that are not listed above.\n` +
231	    `- After writing all files, respond with a brief summary of what was resolved.`
232	  );
233	}
234	
235	/**
236	 * Default implementation: spawns Claude CLI to resolve conflict markers.
237	 * Streams stdout/stderr to process.stdout/stderr.
238	 * Returns true if the process exits with code 0.
239	 */
240	async function defaultInvokeClaudeForResolution(
241	  prompt: string,
242	  cwd: string,
243	  env: NodeJS.ProcessEnv,
244	): Promise<boolean> {
245	  return new Promise((resolve) => {
246	    const child = spawn(
247	      "claude",
248	      [
249	        "-p",
250	        prompt,
251	        "--max-turns",
252	        "10",
253	        "--output-format",
254	        "stream-json",
255	        "--verbose",
256	        "--dangerously-skip-permissions",
257	      ],
258	      { cwd, env, stdio: ["ignore", "pipe", "pipe"] },
259	    );
260	
261	    child.stdout.pipe(process.stdout);
262	    child.stderr.pipe(process.stderr);
263	
264	    child.on("close", (code) => {
265	      resolve(code === 0);
266	    });
267	
268	    child.on("error", () => {
269	      resolve(false);
270	    });
271	  });
272	}
