274	// ── Public API ────────────────────────────────────────────────────────────────
275	
276	/**
277	 * Attempt to rebase the impl branch for one conflicted in_review task.
278	 *
279	 * @returns The outcome of the operation.
280	 */
281	export async function autoRebase(
282	  opts: AutoRebaseOptions,
283	): Promise<AutoRebaseOutcome> {
284	  const {
285	    workspaceRoot,
286	    featureId,
287	    taskId,
288	    taskBranch,
289	    implRepoRoot,
290	    implBaseBranch,
291	    gitAuthorEmail,
292	    gitAuthorName = gitAuthorEmail,
293	    sshKeyPath,
294	    emit,
295	  } = opts;
296	
297	  const env = buildGitCommitEnv(gitAuthorEmail, gitAuthorName, sshKeyPath);
298	  const now = new Date().toISOString();
299	
300	  // ── 1. Claim: ensure we are on the task branch in the management repo ────────
301	  try {
302	    execSync(`git -C "${workspaceRoot}" fetch origin`, { env, stdio: "pipe" });
303	    execSync(
304	      `git -C "${workspaceRoot}" checkout "${taskBranch}"`,
305	      { env, stdio: "pipe" },
306	    );
307	    execSync(
308	      `git -C "${workspaceRoot}" reset --hard "origin/${taskBranch}"`,
309	      { env, stdio: "pipe" },
310	    );
311	  } catch (e) {
312	    emit({
313	      type: "rebase_claim_lost",
314	      task_id: taskId,
315	      feature_id: featureId,
316	      details: `Failed to checkout/reset management repo to task branch: ${String(e)}`,
317	    });
318	    return "claim_lost";
319	  }
320	
321	  // ── 2. Write rebase_started claim to task YAML and push ───────────────────────
322	  let task = readTask(workspaceRoot, featureId, taskId);
323	
324	  // Guard: if conflict_state is already "resolving", another agent claimed it.
325	  if (task.conflict_state === "resolving") {
326	    emit({
327	      type: "rebase_claim_lost",
328	      task_id: taskId,
329	      feature_id: featureId,
330	      details: "conflict_state is already resolving — another agent claimed the rebase.",
331	    });
332	    return "claim_lost";
333	  }
334	
335	  const startedEntry: RebaseLogEntry = {
336	    at: now,
337	    action: "rebase_started",
338	    by: gitAuthorEmail,
339	    note: `Rebase claimed; targeting origin/${implBaseBranch}.`,
340	  };
341	
342	  task.conflict_state = "resolving";
343	  task.rebase_log = [...(task.rebase_log ?? []), startedEntry];
344	  task.execution.last_updated_by = gitAuthorEmail;
345	  task.execution.last_updated_at = now;
346	
347	  writeTask(workspaceRoot, featureId, task);
348	
349	  // First-push-wins: if the push is rejected, another agent got there first.
350	  const relPath = taskYamlRelPath(featureId, taskId);
351	  execSync(`git -C "${workspaceRoot}" add "${relPath}"`, {
352	    env,
353	    stdio: "pipe",
354	  });
355	  execSync(
356	    `git -C "${workspaceRoot}" commit -m "chore(${taskId}): rebase_started — claim"`,
357	    { env, stdio: "pipe" },
358	  );
359	
360	  const claimPush = spawnSync(
361	    "git",
362	    ["-C", workspaceRoot, "push", "origin", taskBranch],
363	    { env, encoding: "utf-8" },
364	  );
365	
366	  if (claimPush.status !== 0) {
367	    emit({
368	      type: "rebase_claim_lost",
369	      task_id: taskId,
370	      feature_id: featureId,
371	      details: `Push rejected — another agent claimed the rebase first. stderr: ${claimPush.stderr}`,
372	    });
373	    return "claim_lost";
374	  }
375	
376	  // ── 3. Rebase in the implementation repo ─────────────────────────────────────
377	  try {
378	    execSync(`git -C "${implRepoRoot}" fetch origin`, { env, stdio: "pipe" });
379	  } catch (e) {
380	    emit({
381	      type: "rebase_blocked",
382	      task_id: taskId,
383	      feature_id: featureId,
384	      details: `git fetch failed in impl repo: ${String(e)}`,
385	    });
386	    // Can't proceed — abort and mark blocked.
387	    return await handleConflictedRebase(
388	      opts,
389	      task,
390	      env,
391	      [`git fetch failed: ${String(e)}`],
392	    );
393	  }
394	
395	  // Ensure we are on the task branch in the impl repo.
396	  try {
397	    execSync(`git -C "${implRepoRoot}" checkout "${taskBranch}"`, {
398	      env,
399	      stdio: "pipe",
400	    });
401	    execSync(
402	      `git -C "${implRepoRoot}" reset --hard "origin/${taskBranch}"`,
403	      { env, stdio: "pipe" },
404	    );
405	  } catch (e) {
406	    emit({
407	      type: "rebase_blocked",
408	      task_id: taskId,
409	      feature_id: featureId,
410	      details: `Failed to checkout impl branch ${taskBranch}: ${String(e)}`,
411	    });
412	    return await handleConflictedRebase(opts, task, env, [`checkout failed: ${String(e)}`]);
413	  }
414	
415	  // Capture agent-authored files BEFORE the rebase so we can compare later.
416	  const agentFiles = listAgentAuthoredFiles(implRepoRoot, implBaseBranch, env);
417	
418	  // Abort any in-progress rebase before starting a new one.
419	  spawnSync("git", ["-C", implRepoRoot, "rebase", "--abort"], {
420	    env,
421	    encoding: "utf-8",
422	  });
423	
424	  const rebaseResult = spawnSync(
425	    "git",
426	    ["-C", implRepoRoot, "rebase", `origin/${implBaseBranch}`],
427	    { env, encoding: "utf-8" },
428	  );
429	
430	  if (rebaseResult.status === 0) {
431	    // ── 4a. Clean rebase ────────────────────────────────────────────────────────
432	    return await handleCleanRebase(opts, task, env);
433	  } else {
434	    // ── 4b. Conflicted rebase — three-tier logic ────────────────────────────────
435	    const conflictedFiles = listConflictedFiles(implRepoRoot, env);
436	    const nonAuthoredConflicts = conflictedFiles.filter(
437	      (f) => !agentFiles.has(f),
438	    );
439	
440	    if (conflictedFiles.length > 0 && nonAuthoredConflicts.length === 0) {
441	      // All conflicts are in agent-authored files — attempt Claude resolution.
442	      emit({
443	        type: "rebase_resolve_attempt",
444	        task_id: taskId,
445	        feature_id: featureId,
446	        conflicted_files: conflictedFiles,
447	      });
448	      const invoker =
449	        opts.invokeClaudeForResolution ?? defaultInvokeClaudeForResolution;
450	      const prompt = buildConflictResolutionPrompt(
451	        implRepoRoot,
452	        implBaseBranch,
453	        conflictedFiles,
454	      );
455	
456	      try {
457	        const resolved = await invoker(prompt, implRepoRoot, env);
458	        if (resolved) {
459	          execSync(`git -C "${implRepoRoot}" add -A`, { env, stdio: "pipe" });
460	          const continueResult = spawnSync(
461	            "git",
462	            ["-C", implRepoRoot, "rebase", "--continue"],
463	            {
464	              env: { ...env, GIT_EDITOR: "true", GIT_SEQUENCE_EDITOR: "true" },
465	              encoding: "utf-8",
466	            },
467	          );
468	          if (continueResult.status === 0) {
469	            emit({
470	              type: "rebase_resolved_by_agent",
471	              task_id: taskId,
472	              feature_id: featureId,
473	              conflicted_files: conflictedFiles,
474	            });
475	            const resolvedAt = new Date().toISOString();
476	            task.rebase_log = [
477	              ...(task.rebase_log ?? []),
478	              {
479	                at: resolvedAt,
480	                action: "rebase_resolved_by_agent",
481	                by: gitAuthorEmail,
482	                note: `Claude resolved conflict markers in: ${conflictedFiles.join(", ")}; rebase continued cleanly.`,
483	              },
484	            ];
485	            return await handleCleanRebase(opts, task, env);
486	          }
487	        }
488	      } catch {
489	        // fall through to block
490	      }
491	      emit({
492	        type: "rebase_resolve_failed",
493	        task_id: taskId,
494	        feature_id: featureId,
495	        conflicted_files: conflictedFiles,
496	      });
497	    }
498	
499	    return await handleConflictedRebase(opts, task, env, conflictedFiles);
500	  }
501	}
502	
503	// ── Clean rebase handler ──────────────────────────────────────────────────────
504	
505	async function handleCleanRebase(
506	  opts: AutoRebaseOptions,
507	  task: Task,
508	  env: NodeJS.ProcessEnv,
509	): Promise<AutoRebaseOutcome> {
510	  const {
511	    workspaceRoot,
512	    featureId,
513	    taskId,
514	    taskBranch,
515	    implRepoRoot,
516	    gitAuthorEmail,
517	    emit,
518	  } = opts;
519	
520	  // Force-push the impl branch.
521	  const pushResult = spawnSync(
522	    "git",
523	    ["-C", implRepoRoot, "push", "--force-with-lease", "origin", taskBranch],
524	    { env, encoding: "utf-8" },
525	  );
526	
527	  if (pushResult.status !== 0) {
528	    emit({
529	      type: "rebase_blocked",
530	      task_id: taskId,
531	      feature_id: featureId,
532	      details: `force-with-lease push failed after clean rebase: ${pushResult.stderr}`,
533	    });
534	    // Rare — treat as a recoverable blocked state.
535	    return await handleConflictedRebase(
536	      opts,
537	      task,
538	      env,
539	      [`force-push failed: ${pushResult.stderr}`],
540	    );
541	  }
542	
543	  // Update task YAML with resolved state.
544	  const completedAt = new Date().toISOString();
545	  const completedEntry: RebaseLogEntry = {
546	    at: completedAt,
547	    action: "rebase_completed",
548	    by: gitAuthorEmail,
549	    note: "Rebase completed cleanly; impl branch force-pushed.",
550	  };
551	
552	  task.conflict_state = "resolved";
553	  task.rebase_log = [...(task.rebase_log ?? []), completedEntry];
554	  task.execution.last_updated_by = gitAuthorEmail;
555	  task.execution.last_updated_at = completedAt;
556	
557	  writeTask(workspaceRoot, featureId, task);
558	
559	  try {
560	    commitAndPushTaskYaml(
561	      workspaceRoot,
562	      featureId,
563	      taskId,
564	      taskBranch,
565	      `chore(${taskId}): rebase_completed — conflict_state resolved`,
566	      env,
567	    );
568	  } catch (e) {
569	    emit({
570	      type: "rebase_completed",
571	      task_id: taskId,
572	      feature_id: featureId,
573	      note: "Rebase clean but management repo push failed — YAML may be stale.",
574	      details: String(e),
575	    });
576	    return "rebase_completed";
577	  }
578	
579	  emit({
580	    type: "rebase_completed",
581	    task_id: taskId,
582	    feature_id: featureId,
583	  });
584	
585	  return "rebase_completed";
586	}
587	
588	// ── Conflicted rebase handler ─────────────────────────────────────────────────
589	
590	async function handleConflictedRebase(
591	  opts: AutoRebaseOptions,
592	  task: Task,
593	  env: NodeJS.ProcessEnv,
594	  conflictedFiles: string[],
595	): Promise<AutoRebaseOutcome> {
596	  const {
597	    workspaceRoot,
598	    featureId,
599	    taskId,
600	    taskBranch,
601	    implRepoRoot,
602	    gitAuthorEmail,
603	    emit,
604	  } = opts;
605	
606	  // Abort any ongoing rebase so git is in a clean-enough state.
607	  spawnSync("git", ["-C", implRepoRoot, "rebase", "--abort"], {
608	    env,
609	    encoding: "utf-8",
610	  });
611	
612	  // Stage everything (including conflict markers) and commit.
613	  spawnSync("git", ["-C", implRepoRoot, "add", "-A"], {
614	    env,
615	    encoding: "utf-8",
616	  });
617	
618	  const conflictSummary =
619	    conflictedFiles.length > 0
620	      ? conflictedFiles.join(", ")
621	      : "unknown files";
622	
623	  const commitResult = spawnSync(
624	    "git",
625	    [
626	      "-C",
627	      implRepoRoot,
628	      "commit",
629	      "-m",
630	      `wip(${taskId}): conflict markers after failed rebase — ${conflictSummary}`,
631	    ],
632	    { env, encoding: "utf-8" },
633	  );
634	
635	  // Push even if commit was a no-op (nothing staged).
636	  if (commitResult.status === 0) {
637	    spawnSync(
638	      "git",
639	      ["-C", implRepoRoot, "push", "origin", taskBranch],
640	      { env, encoding: "utf-8" },
641	    );
642	  }
643	
644	  // Build the blocked_suggestion with file:line pointers.
645	  const blockedNote =
646	    conflictedFiles.length > 0
647	      ? `Unresolvable merge conflicts in: ${conflictedFiles.join("; ")}. Manual resolution required.`
648	      : "Merge conflicts detected during rebase. Manual resolution required.";
649	
650	  const blockedAt = new Date().toISOString();
651	  const blockedEntry: RebaseLogEntry = {
652	    at: blockedAt,
653	    action: "rebase_blocked",
654	    by: gitAuthorEmail,
655	    note: blockedNote,
656	  };
657	
658	  task.status = "blocked";
659	  task.blocked_reason = "pr_conflict";
660	  // "resolved" signals that the conflict has been surfaced to the branch and
661	  // is visible in the PR — not that it has been fixed. See technical-design.md.
662	  task.conflict_state = "resolved";
663	  task.rebase_log = [...(task.rebase_log ?? []), blockedEntry];
664	  task.execution.last_updated_by = gitAuthorEmail;
665	  task.execution.last_updated_at = blockedAt;
666	  task.execution.suggested_next_step =
667	    "Manually resolve the conflicts listed in blocked_reason detail, then set status back to in_review.";
668	  task.log.push({
669	    action: "blocked",
670	    by: gitAuthorEmail,
671	    at: blockedAt,
672	    note: blockedNote,
673	  });
674	
675	  writeTask(workspaceRoot, featureId, task);
676	
677	  try {
678	    commitAndPushTaskYaml(
679	      workspaceRoot,
680	      featureId,
681	      taskId,
682	      taskBranch,
683	      `chore(${taskId}): rebase_blocked — pr_conflict`,
684	      env,
685	    );
686	  } catch (e) {
687	    emit({
688	      type: "rebase_blocked",
689	      task_id: taskId,
690	      feature_id: featureId,
691	      conflicted_files: conflictedFiles,
692	      note: "Management repo YAML push failed — YAML may be stale.",
693	      details: String(e),
694	    });
695	    return "rebase_blocked";
696	  }
697	
698	  emit({
699	    type: "rebase_blocked",
700	    task_id: taskId,
701	    feature_id: featureId,
702	    conflicted_files: conflictedFiles,
703	  });
704	
705	  return "rebase_blocked";
706	}
