708	// ── Cycle-level orchestrator ──────────────────────────────────────────────────
709	
710	export interface HandleMergeConflictsOptions {
711	  /** Results from checkInReviewPrs — only those with mergeable === false are processed. */
712	  prResults: PrStatusResult[];
713	  /** Absolute path to the management (workspace) repo root — keyed by workspaceRoot. */
714	  workspaceRoot: string;
715	  /** Resolve the impl repo root for a given repo ID (from workspace.yaml). */
716	  resolveImplRepoRoot: (repoId: string) => string;
717	  /** Resolve the impl base branch for a given repo ID (from workspace.yaml). */
718	  resolveImplBaseBranch: (repoId: string) => string;
719	  /** Resolve the task's repo ID from the task YAML. */
720	  resolveTaskRepoId: (featureId: string, taskId: string) => string;
721	  /** GIT_AUTHOR_EMAIL for commits and log entries. */
722	  gitAuthorEmail: string;
723	  /** GIT_AUTHOR_NAME for commits. Defaults to gitAuthorEmail. */
724	  gitAuthorName?: string;
725	  /** SSH private key path for git push operations. */
726	  sshKeyPath?: string;
727	  /** Structured event emitter for observability. */
728	  emit: (event: Record<string, unknown>) => void;
729	}
730	
731	/**
732	 * Iterate T2 poll results where `mergeable === false` and run autoRebase for each.
733	 * Called from `runOneCycle` in main.ts after the ready-task pass.
734	 */
735	export async function handleMergeConflicts(
736	  opts: HandleMergeConflictsOptions,
737	): Promise<void> {
738	  const {
739	    prResults,
740	    workspaceRoot,
741	    resolveImplRepoRoot,
742	    resolveImplBaseBranch,
743	    resolveTaskRepoId,
744	    gitAuthorEmail,
745	    gitAuthorName,
746	    sshKeyPath,
747	    emit,
748	  } = opts;
749	
750	  const conflicted = prResults.filter((r) => r.mergeable === false);
751	
752	  // Only process one conflicted task per impl repo per cycle to prevent
753	  // concurrent git rebase operations on the same on-disk clone.
754	  const processedImplRoots = new Set<string>();
755	
756	  for (const result of conflicted) {
757	    const { taskId, featureId } = result;
758	
759	    let repoId: string;
760	    try {
761	      repoId = resolveTaskRepoId(featureId, taskId);
762	    } catch (e) {
763	      emit({
764	        type: "rebase_blocked",
765	        task_id: taskId,
766	        feature_id: featureId,
