/**
 * T3: Auto-rebase handler.
 *
 * When the in_review poll (T2) reports `mergeable: false` for a task, this
 * handler:
 *
 *   1. Claims the rebase work via a first-push-wins mechanism: appends a
 *      `rebase_started` log entry to the task YAML on the management-repo
 *      feature branch and pushes. If the push is rejected, another agent
 *      claimed first — skip this cycle (`rebase_claim_lost`).
 *
 *   2. In the implementation repo: `git fetch origin` then
 *      `git rebase origin/<base_branch>`.
 *
 *   3. Clean rebase (exit 0):
 *        - `git push --force-with-lease` the impl branch.
 *        - Update task YAML: `conflict_state: resolved`, append
 *          `rebase_completed` log entry.
 *        - Push the management repo feature branch.
 *        - Emit `rebase_completed`.
 *
 *   4. Conflicted rebase (exit ≠ 0) — three-tier logic:
 *
 *      a. If ALL conflicted files are in files the agent authored on this
 *         branch (`git diff --name-only origin/<base>...HEAD`):
 *           - Emit `rebase_resolve_attempt`.
 *           - Spawn Claude to resolve the conflict markers in each file.
 *           - Run `git add -A` then `git rebase --continue`.
 *           - If continue succeeds: treat as a clean rebase (force-push,
 *             mark resolved). Emit `rebase_resolved_by_agent`.
 *           - If Claude fails or continue fails: emit `rebase_resolve_failed`
 *             and fall through to block path.
 *
 *      b. If ANY conflicted file was NOT authored by the agent:
 *           - Block immediately (human-owned files must not be auto-modified).
 *
 *      c. Block path:
 *           - Stage all conflict markers (`git add -A`).
 *           - Commit with a descriptive message.
 *           - Push the impl branch.
 *           - Update task YAML: `status: blocked`,
 *             `blocked_reason: pr_conflict`, `conflict_state: conflicted`,
 *             append `rebase_blocked` log entry with file:line pointers.
 *           - Push the management repo feature branch.
 *           - Emit `rebase_blocked`.
 */

import { execSync, spawnSync, spawn } from "node:child_process";
import { readFileSync, writeFileSync } from "node:fs";
import { parse as parseYaml, stringify as yamlStringify } from "yaml";
import type { Task, RebaseLogEntry } from "../types/task.js";
import { taskYamlAbsPath, taskYamlRelPath } from "../paths.js";
import type { PrStatusResult } from "../poll/check-in-review-prs.js";
import { buildGitCommitEnv } from "../git-env.js";

// ── Public types ──────────────────────────────────────────────────────────────

export interface AutoRebaseOptions {
  /** Absolute path to the management (workspace) repo root. */
  workspaceRoot: string;
  /** Feature directory ID (e.g. "agent-pr-response"). */
  featureId: string;
  /** Task ID (e.g. "T3"). */
  taskId: string;
  /** Task feature branch name (e.g. "feature/agent-pr-response-T3"). */
  taskBranch: string;
  /** Absolute path to the implementation repo root. */
  implRepoRoot: string;
  /**
   * Base branch of the implementation repo (e.g. "main").
   * The rebase targets `origin/<implBaseBranch>`.
   */
  implBaseBranch: string;
  /** GIT_AUTHOR_EMAIL for commits and log entries. */
  gitAuthorEmail: string;
  /** GIT_AUTHOR_NAME for commits. Defaults to gitAuthorEmail. */
  gitAuthorName?: string;
  /** SSH private key path for git push operations. */
  sshKeyPath?: string;
  /** Structured event emitter for observability. */
  emit: (event: Record<string, unknown>) => void;
  /**
   * Optional override for spawning Claude to resolve conflicts.
   * Receives the prompt string, the impl repo cwd, and the process env.
   * Returns true if resolution succeeded, false otherwise.
   * Defaults to `defaultInvokeClaudeForResolution`.
   */
  invokeClaudeForResolution?: (
    prompt: string,
    cwd: string,
    env: NodeJS.ProcessEnv,
  ) => Promise<boolean>;
}

export type AutoRebaseOutcome =
  | "claim_lost"        // Another agent already claimed the rebase.
  | "rebase_completed"  // Rebase was clean; impl branch force-pushed.
  | "rebase_blocked";   // Conflicts remain; task set to blocked.

// ── Internal helpers ──────────────────────────────────────────────────────────


function readTask(
  workspaceRoot: string,
  featureId: string,
  taskId: string,
): Task {
  return parseYaml(
    readFileSync(taskYamlAbsPath(workspaceRoot, featureId, taskId), "utf-8"),
  ) as Task;
}

function writeTask(
  workspaceRoot: string,
  featureId: string,
  task: Task,
): void {
  writeFileSync(
    taskYamlAbsPath(workspaceRoot, featureId, task.id),
    yamlStringify(task),
    "utf-8",
  );
}

/**
 * Commit and push the updated task YAML to the management repo task branch.
 * Non-fatal: logs errors via emit but does not throw.
 */
function commitAndPushTaskYaml(
  workspaceRoot: string,
  featureId: string,
  taskId: string,
  taskBranch: string,
  commitMessage: string,
  env: NodeJS.ProcessEnv,
): void {
  const relPath = taskYamlRelPath(featureId, taskId);
  execSync(`git -C "${workspaceRoot}" add "${relPath}"`, {
    env,
    stdio: "pipe",
  });
  execSync(
    `git -C "${workspaceRoot}" commit -m "${commitMessage}"`,
    { env, stdio: "pipe" },
  );
  execSync(
    `git -C "${workspaceRoot}" push origin "${taskBranch}"`,
    { env, stdio: "pipe" },
  );
}

/**
 * Return all files that currently have conflict markers via `git diff --name-only`.
 * Falls back to an empty array on error.
 */
function listConflictedFiles(
  implRepoRoot: string,
  env: NodeJS.ProcessEnv,
): string[] {
  try {
    const output = execSync(
      `git -C "${implRepoRoot}" diff --name-only --diff-filter=U`,
      { env, encoding: "utf-8", stdio: ["ignore", "pipe", "pipe"] },
    ).trim();
    return output ? output.split("\n") : [];
  } catch {
    return [];
  }
}

/**
 * Return the set of files the agent has touched on this branch relative to
 * origin/<baseBranch>. Uses `git diff --name-only origin/<base>...HEAD`.
 * Falls back to an empty Set on error.
 */
function listAgentAuthoredFiles(
  implRepoRoot: string,
  baseBranch: string,
  env: NodeJS.ProcessEnv,
): Set<string> {
  try {
    const output = execSync(
      `git -C "${implRepoRoot}" diff --name-only origin/${baseBranch}...HEAD`,
      { env, encoding: "utf-8", stdio: ["ignore", "pipe", "pipe"] },
    ).trim();
    return new Set(output ? output.split("\n") : []);
  } catch {
    return new Set();
  }
}

/**
 * Build the prompt to send to Claude for resolving conflict markers.
 * For dependency manifest files, instruct a union merge.
 * For other files, instruct preservation of all functionality from both sides.
 */
function buildConflictResolutionPrompt(
  implRepoRoot: string,
  baseBranch: string,
  conflictedFiles: string[],
): string {
  const depFiles = new Set([
    "pyproject.toml",
    "requirements.txt",
    "package.json",
    "go.mod",
    "Cargo.toml",
  ]);

  const fileInstructions = conflictedFiles
    .map((f) => {
      const basename = f.split("/").pop() ?? f;
      if (depFiles.has(basename)) {
        return `- ${f}: dependency manifest — take the UNION of both sides (include all packages/versions from both HEAD and ${baseBranch}, keeping the higher version where there are conflicts)`;
      }
      return `- ${f}: preserve ALL functionality from both sides; do not drop any code`;
    })
    .join("\n");

  return (
    `You are resolving git merge conflicts after a rebase in the repository at ${implRepoRoot}.\n` +
    `The following files contain conflict markers (<<<<<<<, =======, >>>>>>>):\n\n` +
    fileInstructions +
    `\n\nFor each file:\n` +
    `1. Read the file contents (which include conflict markers).\n` +
    `2. Resolve the conflict markers according to the instructions above.\n` +
    `3. Write the fully resolved content back to disk.\n\n` +
    `IMPORTANT:\n` +
    `- Do NOT run git add or git commit — only write the resolved file contents.\n` +
    `- Do NOT modify any files that are not listed above.\n` +
    `- After writing all files, respond with a brief summary of what was resolved.`
  );
}

/**
 * Default implementation: spawns Claude CLI to resolve conflict markers.
 * Streams stdout/stderr to process.stdout/stderr.
 * Returns true if the process exits with code 0.
 */
async function defaultInvokeClaudeForResolution(
  prompt: string,
  cwd: string,
  env: NodeJS.ProcessEnv,
): Promise<boolean> {
  return new Promise((resolve) => {
    const child = spawn(
      "claude",
      [
        "-p",
        prompt,
        "--max-turns",
        "10",
        "--output-format",
        "stream-json",
        "--verbose",
        "--dangerously-skip-permissions",
      ],
      { cwd, env, stdio: ["ignore", "pipe", "pipe"] },
    );

    child.stdout.pipe(process.stdout);
    child.stderr.pipe(process.stderr);

    child.on("close", (code) => {
      resolve(code === 0);
    });

    child.on("error", () => {
      resolve(false);
    });
  });
}

// ── Public API ────────────────────────────────────────────────────────────────

/**
 * Attempt to rebase the impl branch for one conflicted in_review task.
 *
 * @returns The outcome of the operation.
 */
export async function autoRebase(
  opts: AutoRebaseOptions,
): Promise<AutoRebaseOutcome> {
  const {
    workspaceRoot,
    featureId,
    taskId,
    taskBranch,
    implRepoRoot,
    implBaseBranch,
    gitAuthorEmail,
    gitAuthorName = gitAuthorEmail,
    sshKeyPath,
    emit,
  } = opts;

  const env = buildGitCommitEnv(gitAuthorEmail, gitAuthorName, sshKeyPath);
  const now = new Date().toISOString();

  // ── 1. Claim: ensure we are on the task branch in the management repo ────────
  try {
    execSync(`git -C "${workspaceRoot}" fetch origin`, { env, stdio: "pipe" });
    execSync(
      `git -C "${workspaceRoot}" checkout "${taskBranch}"`,
      { env, stdio: "pipe" },
    );
    execSync(
      `git -C "${workspaceRoot}" reset --hard "origin/${taskBranch}"`,
      { env, stdio: "pipe" },
    );
  } catch (e) {
    emit({
      type: "rebase_claim_lost",
      task_id: taskId,
      feature_id: featureId,
      details: `Failed to checkout/reset management repo to task branch: ${String(e)}`,
    });
    return "claim_lost";
  }

  // ── 2. Write rebase_started claim to task YAML and push ───────────────────────
  let task = readTask(workspaceRoot, featureId, taskId);

  // Guard: if conflict_state is already "resolving", another agent claimed it.
  if (task.conflict_state === "resolving") {
    emit({
      type: "rebase_claim_lost",
      task_id: taskId,
      feature_id: featureId,
      details: "conflict_state is already resolving — another agent claimed the rebase.",
    });
    return "claim_lost";
  }

  const startedEntry: RebaseLogEntry = {
    at: now,
    action: "rebase_started",
    by: gitAuthorEmail,
    note: `Rebase claimed; targeting origin/${implBaseBranch}.`,
  };

  task.conflict_state = "resolving";
  task.rebase_log = [...(task.rebase_log ?? []), startedEntry];
  task.execution.last_updated_by = gitAuthorEmail;
  task.execution.last_updated_at = now;

  writeTask(workspaceRoot, featureId, task);

  // First-push-wins: if the push is rejected, another agent got there first.
  const relPath = taskYamlRelPath(featureId, taskId);
  execSync(`git -C "${workspaceRoot}" add "${relPath}"`, {
    env,
    stdio: "pipe",
  });
  execSync(
    `git -C "${workspaceRoot}" commit -m "chore(${taskId}): rebase_started — claim"`,
    { env, stdio: "pipe" },
  );

  const claimPush = spawnSync(
    "git",
    ["-C", workspaceRoot, "push", "origin", taskBranch],
    { env, encoding: "utf-8" },
  );

  if (claimPush.status !== 0) {
    emit({
      type: "rebase_claim_lost",
      task_id: taskId,
      feature_id: featureId,
      details: `Push rejected — another agent claimed the rebase first. stderr: ${claimPush.stderr}`,
    });
    return "claim_lost";
  }

  // ── 3. Rebase in the implementation repo ─────────────────────────────────────
  try {
    execSync(`git -C "${implRepoRoot}" fetch origin`, { env, stdio: "pipe" });
  } catch (e) {
    emit({
      type: "rebase_blocked",
      task_id: taskId,
      feature_id: featureId,
      details: `git fetch failed in impl repo: ${String(e)}`,
    });
    // Can't proceed — abort and mark blocked.
    return await handleConflictedRebase(
      opts,
      task,
      env,
      [`git fetch failed: ${String(e)}`],
    );
  }

  // Ensure we are on the task branch in the impl repo.
  try {
    execSync(`git -C "${implRepoRoot}" checkout "${taskBranch}"`, {
      env,
      stdio: "pipe",
    });
    execSync(
      `git -C "${implRepoRoot}" reset --hard "origin/${taskBranch}"`,
      { env, stdio: "pipe" },
    );
  } catch (e) {
    emit({
      type: "rebase_blocked",
      task_id: taskId,
      feature_id: featureId,
      details: `Failed to checkout impl branch ${taskBranch}: ${String(e)}`,
    });
    return await handleConflictedRebase(opts, task, env, [`checkout failed: ${String(e)}`]);
  }

  // Capture agent-authored files BEFORE the rebase so we can compare later.
  const agentFiles = listAgentAuthoredFiles(implRepoRoot, implBaseBranch, env);

  // Abort any in-progress rebase before starting a new one.
  spawnSync("git", ["-C", implRepoRoot, "rebase", "--abort"], {
    env,
    encoding: "utf-8",
  });

  const rebaseResult = spawnSync(
    "git",
    ["-C", implRepoRoot, "rebase", `origin/${implBaseBranch}`],
    { env, encoding: "utf-8" },
  );

  if (rebaseResult.status === 0) {
    // ── 4a. Clean rebase ────────────────────────────────────────────────────────
    return await handleCleanRebase(opts, task, env);
  } else {
    // ── 4b. Conflicted rebase — three-tier logic ────────────────────────────────
    const conflictedFiles = listConflictedFiles(implRepoRoot, env);
    const nonAuthoredConflicts = conflictedFiles.filter(
      (f) => !agentFiles.has(f),
    );

    if (conflictedFiles.length > 0 && nonAuthoredConflicts.length === 0) {
      // All conflicts are in agent-authored files — attempt Claude resolution.
      emit({
        type: "rebase_resolve_attempt",
        task_id: taskId,
        feature_id: featureId,
        conflicted_files: conflictedFiles,
      });
      const invoker =
        opts.invokeClaudeForResolution ?? defaultInvokeClaudeForResolution;
      const prompt = buildConflictResolutionPrompt(
        implRepoRoot,
        implBaseBranch,
        conflictedFiles,
      );

      try {
        const resolved = await invoker(prompt, implRepoRoot, env);
        if (resolved) {
          execSync(`git -C "${implRepoRoot}" add -A`, { env, stdio: "pipe" });
          const continueResult = spawnSync(
            "git",
            ["-C", implRepoRoot, "rebase", "--continue"],
            {
              env: { ...env, GIT_EDITOR: "true", GIT_SEQUENCE_EDITOR: "true" },
              encoding: "utf-8",
            },
          );
          if (continueResult.status === 0) {
            emit({
              type: "rebase_resolved_by_agent",
              task_id: taskId,
              feature_id: featureId,
              conflicted_files: conflictedFiles,
            });
            const resolvedAt = new Date().toISOString();
            task.rebase_log = [
              ...(task.rebase_log ?? []),
              {
                at: resolvedAt,
                action: "rebase_resolved_by_agent",
                by: gitAuthorEmail,
                note: `Claude resolved conflict markers in: ${conflictedFiles.join(", ")}; rebase continued cleanly.`,
              },
            ];
            return await handleCleanRebase(opts, task, env);
          }
        }
      } catch {
        // fall through to block
      }
      emit({
        type: "rebase_resolve_failed",
        task_id: taskId,
        feature_id: featureId,
        conflicted_files: conflictedFiles,
      });
    }

    return await handleConflictedRebase(opts, task, env, conflictedFiles);
  }
}

// ── Clean rebase handler ──────────────────────────────────────────────────────

async function handleCleanRebase(
  opts: AutoRebaseOptions,
  task: Task,
  env: NodeJS.ProcessEnv,
): Promise<AutoRebaseOutcome> {
  const {
    workspaceRoot,
    featureId,
    taskId,
    taskBranch,
    implRepoRoot,
    gitAuthorEmail,
    emit,
  } = opts;

  // Force-push the impl branch.
  const pushResult = spawnSync(
    "git",
    ["-C", implRepoRoot, "push", "--force-with-lease", "origin", taskBranch],
    { env, encoding: "utf-8" },
  );

  if (pushResult.status !== 0) {
    emit({
      type: "rebase_blocked",
      task_id: taskId,
      feature_id: featureId,
      details: `force-with-lease push failed after clean rebase: ${pushResult.stderr}`,
    });
    // Rare — treat as a recoverable blocked state.
    return await handleConflictedRebase(
      opts,
      task,
      env,
      [`force-push failed: ${pushResult.stderr}`],
    );
  }

  // Update task YAML with resolved state.
  const completedAt = new Date().toISOString();
  const completedEntry: RebaseLogEntry = {
    at: completedAt,
    action: "rebase_completed",
    by: gitAuthorEmail,
    note: "Rebase completed cleanly; impl branch force-pushed.",
  };

  task.conflict_state = "resolved";
  task.rebase_log = [...(task.rebase_log ?? []), completedEntry];
  task.execution.last_updated_by = gitAuthorEmail;
  task.execution.last_updated_at = completedAt;

  writeTask(workspaceRoot, featureId, task);

  try {
    commitAndPushTaskYaml(
      workspaceRoot,
      featureId,
      taskId,
      taskBranch,
      `chore(${taskId}): rebase_completed — conflict_state resolved`,
      env,
    );
  } catch (e) {
    emit({
      type: "rebase_completed",
      task_id: taskId,
      feature_id: featureId,
      note: "Rebase clean but management repo push failed — YAML may be stale.",
      details: String(e),
    });
    return "rebase_completed";
  }

  emit({
    type: "rebase_completed",
    task_id: taskId,
    feature_id: featureId,
  });

  return "rebase_completed";
}

// ── Conflicted rebase handler ─────────────────────────────────────────────────

async function handleConflictedRebase(
  opts: AutoRebaseOptions,
  task: Task,
  env: NodeJS.ProcessEnv,
  conflictedFiles: string[],
): Promise<AutoRebaseOutcome> {
  const {
    workspaceRoot,
    featureId,
    taskId,
    taskBranch,
    implRepoRoot,
    gitAuthorEmail,
    emit,
  } = opts;

  // Abort any ongoing rebase so git is in a clean-enough state.
  spawnSync("git", ["-C", implRepoRoot, "rebase", "--abort"], {
    env,
    encoding: "utf-8",
  });

  // Stage everything (including conflict markers) and commit.
  spawnSync("git", ["-C", implRepoRoot, "add", "-A"], {
    env,
    encoding: "utf-8",
  });

  const conflictSummary =
    conflictedFiles.length > 0
      ? conflictedFiles.join(", ")
      : "unknown files";

  const commitResult = spawnSync(
    "git",
    [
      "-C",
      implRepoRoot,
      "commit",
      "-m",
      `wip(${taskId}): conflict markers after failed rebase — ${conflictSummary}`,
    ],
    { env, encoding: "utf-8" },
  );

  // Push even if commit was a no-op (nothing staged).
  if (commitResult.status === 0) {
    spawnSync(
      "git",
      ["-C", implRepoRoot, "push", "origin", taskBranch],
      { env, encoding: "utf-8" },
    );
  }

  // Build the blocked_suggestion with file:line pointers.
  const blockedNote =
    conflictedFiles.length > 0
      ? `Unresolvable merge conflicts in: ${conflictedFiles.join("; ")}. Manual resolution required.`
      : "Merge conflicts detected during rebase. Manual resolution required.";

  const blockedAt = new Date().toISOString();
  const blockedEntry: RebaseLogEntry = {
    at: blockedAt,
    action: "rebase_blocked",
    by: gitAuthorEmail,
    note: blockedNote,
  };

  task.status = "blocked";
  task.blocked_reason = "pr_conflict";
  // "resolved" signals that the conflict has been surfaced to the branch and
  // is visible in the PR — not that it has been fixed. See technical-design.md.
  task.conflict_state = "resolved";
  task.rebase_log = [...(task.rebase_log ?? []), blockedEntry];
  task.execution.last_updated_by = gitAuthorEmail;
  task.execution.last_updated_at = blockedAt;
  task.execution.suggested_next_step =
    "Manually resolve the conflicts listed in blocked_reason detail, then set status back to in_review.";
  task.log.push({
    action: "blocked",
    by: gitAuthorEmail,
    at: blockedAt,
    note: blockedNote,
  });

  writeTask(workspaceRoot, featureId, task);

  try {
    commitAndPushTaskYaml(
      workspaceRoot,
      featureId,
      taskId,
      taskBranch,
      `chore(${taskId}): rebase_blocked — pr_conflict`,
      env,
    );
  } catch (e) {
    emit({
      type: "rebase_blocked",
      task_id: taskId,
      feature_id: featureId,
      conflicted_files: conflictedFiles,
      note: "Management repo YAML push failed — YAML may be stale.",
      details: String(e),
    });
    return "rebase_blocked";
  }

  emit({
    type: "rebase_blocked",
    task_id: taskId,
    feature_id: featureId,
    conflicted_files: conflictedFiles,
  });

  return "rebase_blocked";
}

// ── Cycle-level orchestrator ──────────────────────────────────────────────────

export interface HandleMergeConflictsOptions {
  /** Results from checkInReviewPrs — only those with mergeable === false are processed. */
  prResults: PrStatusResult[];
  /** Absolute path to the management (workspace) repo root — keyed by workspaceRoot. */
  workspaceRoot: string;
  /** Resolve the impl repo root for a given repo ID (from workspace.yaml). */
  resolveImplRepoRoot: (repoId: string) => string;
  /** Resolve the impl base branch for a given repo ID (from workspace.yaml). */
  resolveImplBaseBranch: (repoId: string) => string;
  /** Resolve the task's repo ID from the task YAML. */
  resolveTaskRepoId: (featureId: string, taskId: string) => string;
  /** GIT_AUTHOR_EMAIL for commits and log entries. */
  gitAuthorEmail: string;
  /** GIT_AUTHOR_NAME for commits. Defaults to gitAuthorEmail. */
  gitAuthorName?: string;
  /** SSH private key path for git push operations. */
  sshKeyPath?: string;
  /** Structured event emitter for observability. */
  emit: (event: Record<string, unknown>) => void;
}

/**
 * Iterate T2 poll results where `mergeable === false` and run autoRebase for each.
 * Called from `runOneCycle` in main.ts after the ready-task pass.
 */
export async function handleMergeConflicts(
  opts: HandleMergeConflictsOptions,
): Promise<void> {
  const {
    prResults,
    workspaceRoot,
    resolveImplRepoRoot,
    resolveImplBaseBranch,
    resolveTaskRepoId,
    gitAuthorEmail,
    gitAuthorName,
    sshKeyPath,
    emit,
  } = opts;

  const conflicted = prResults.filter((r) => r.mergeable === false);

  // Only process one conflicted task per impl repo per cycle to prevent
  // concurrent git rebase operations on the same on-disk clone.
  const processedImplRoots = new Set<string>();

  for (const result of conflicted) {
    const { taskId, featureId } = result;

    let repoId: string;
    try {
      repoId = resolveTaskRepoId(featureId, taskId);
    } catch (e) {
      emit({
        type: "rebase_blocked",
        task_id: taskId,
        feature_id: featureId,
        details: `Cannot resolve repo ID: ${String(e)}`,
      });
      continue;
    }

    let implRepoRoot: string;
    let implBaseBranch: string;
    try {
      implRepoRoot = resolveImplRepoRoot(repoId);
      implBaseBranch = resolveImplBaseBranch(repoId);
    } catch (e) {
      emit({
        type: "rebase_blocked",
        task_id: taskId,
        feature_id: featureId,
        details: `Cannot resolve impl repo path or base branch: ${String(e)}`,
      });
      continue;
    }

    if (processedImplRoots.has(implRepoRoot)) {
      emit({
        type: "rebase_skipped_concurrent",
        task_id: taskId,
        feature_id: featureId,
        details: `impl repo ${implRepoRoot} already has a rebase in progress this cycle — skipping to prevent concurrent git operations`,
      });
      continue;
    }
    processedImplRoots.add(implRepoRoot);

    const taskBranch = `feature/${featureId}-${taskId}`;

    try {
      await autoRebase({
        workspaceRoot,
        featureId,
        taskId,
        taskBranch,
        implRepoRoot,
        implBaseBranch,
        gitAuthorEmail,
        gitAuthorName,
        sshKeyPath,
        emit,
      });
    } catch (e) {
      emit({
        type: "rebase_blocked",
        task_id: taskId,
        feature_id: featureId,
        details: `Unexpected error in autoRebase: ${String(e)}`,
      });
    }
  }
}

