/**
 * Tests for pr-response/auto-rebase.ts
 *
 * Unit tests only — no real git operations. `execSync` and `spawnSync` are
 * mocked via vi.mock. Filesystem operations use real temp directories.
 *
 * Covers:
 *   1. autoRebase — claim_lost when checkout of task branch fails
 *   2. autoRebase — claim_lost when task conflict_state is already "resolving"
 *   3. autoRebase — claim_lost when push of claim commit is rejected
 *   4. autoRebase — rebase_completed on clean rebase
 *   5. autoRebase — rebase_blocked on conflicted rebase (conflicts NOT in agent files)
 *   6. autoRebase — rebase_blocked when fetch fails in impl repo
 *   7. handleMergeConflicts — only processes tasks with mergeable === false
 *   8. handleMergeConflicts — skips tasks with mergeable === true or null
 *   9. autoRebase — rebase_completed after agent successfully resolves author-owned conflicts
 *  10. autoRebase — rebase_blocked when Claude resolution fails
 *  11. autoRebase — rebase_blocked immediately when some conflicts are not in agent-authored files
 */

import { describe, it, expect, vi, afterEach, beforeEach } from "vitest";
import {
  mkdtempSync,
  mkdirSync,
  writeFileSync,
  readFileSync,
  rmSync,
} from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { execSync, spawnSync } from "node:child_process";
