tool_use_result.originalFile:
/**
 * Per-cycle in_review PR status poller.
 *
 * For every `in_review` task across all watched workspaces, calls the GitHub
 * GraphQL API to fetch: mergeable state, draft state, and unresolved inline
 * review threads.
 *
 * General PR-level issue comments are intentionally ignored — they are not
 * trackable without identity-dependent heuristics and cause dispatch loops.
 * Only inline review threads (which have a first-class `isResolved` bit on
 * GitHub's side) are used to determine whether a review agent should run.
 *
 * Pure read — no task YAML mutations.
 *
 * On API errors, emits `in_review_poll_error` and skips that task.
 * Results are passed to the T3 (auto-rebase) and T4 (open-comment) handlers.
 */

import { existsSync, readFileSync, readdirSync } from "node:fs";
import { join } from "node:path";
import { spawnSync } from "node:child_process";
import { parse as parseYaml } from "yaml";
import type { Task } from "../types/task.js";
import { featuresRoot, TASKS_DIR, taskBranchName, taskYamlRelPath } from "../paths.js";
import { TERMINAL_STATUSES, tryReadTaskFromBranch } from "../task-branch-state.js";

// ── Public types ──────────────────────────────────────────────────────────────

/** Status reported by the GitHub GraphQL API for a single in_review task's PR. */
export interface PrStatusResult {
  taskId: string;
  featureId: string;
  /** Absolute path to the management workspace that owns this task. */
  workspaceRoot: string;
  /**
   * Whether the PR can be cleanly merged into the base branch.
   * null means GitHub has not finished computing the mergeability yet.
   */
  mergeable: boolean | null;
  /** True when the PR is in draft state. */
  draft: boolean;
  /**
   * True when the PR has at least one unresolved inline review thread.
   * General PR-level issue comments are not tracked.
   * This is the trigger for dispatching the respond-to-review agent.
   */
  hasOpenComments: boolean;
}

export interface CheckInReviewPrsOptions {
  /** Absolute paths to management workspace repos to scan. */
  workspaceRoots: string[];
  /** GitHub personal access token for API authentication. */
  githubToken: string;
  emit: (event: Record<string, unknown>) => void;
}

// ── Internal helpers ──────────────────────────────────────────────────────────

/**
 * Parse owner, repo, and pull number from a GitHub PR URL.
 * Accepts https://github.com/{owner}/{repo}/pull/{number}
 * Returns null for any non-matching URL.
 */
export function parsePrUrl(
  url: string,
): { owner: string; repo: string; pullNumber: number } | null {
  const match = /https?:\/\/github\.com\/([^/]+)\/([^/]+)\/pull\/(\d+)/.exec(url);
  if (!match) return null;
  return {
    owner: match[1],
    repo: match[2],
    pullNumber: parseInt(match[3], 10),
  };
}

interface GitHubGraphQLPrData {
  isDraft: boolean;
  mergeable: "MERGEABLE" | "CONFLICTING" | "UNKNOWN";
  reviewThreads: { nodes: Array<{ isResolved: boolean }> };
}

interface GitHubGraphQLResponse {
  data?: { repository?: { pullRequest?: GitHubGraphQLPrData | null } | null };
  errors?: Array<{ message: string }>;
}

const PR_STATUS_QUERY = `
query($owner: String!, $name: String!, $number: Int!) {
  repository(owner: $owner, name: $name) {
    pullRequest(number: $number) {
      isDraft
      mergeable
      reviewThreads(first: 100) { nodes { isResolved } }
    }
  }
}`.trim();

/**
 * Call the GitHub GraphQL API via curl to get PR status and unresolved review threads.
 * Throws on curl failure, empty response, or GraphQL errors.
 */
function fetchPrStatus(
  owner: string,
  repo: string,
  pullNumber: number,
  githubToken: string,
): { draft: boolean; mergeable: boolean | null; hasOpenComments: boolean } {
  const body = JSON.stringify({
    query: PR_STATUS_QUERY,
    variables: { owner, name: repo, number: pullNumber },
  });

  const result = spawnSync(
    "curl",
    [
      "-s", "-X", "POST",
      "-H", `Authorization: Bearer ${githubToken}`,
      "-H", "Content-Type: application/json",
      "-H", "Accept: application/vnd.github+json",
      "-d", body,
      "https://api.github.com/graphql",
    ],
    { encoding: "utf-8", stdio: ["ignore", "pipe", "pipe"] },
  );

  if (result.error) throw result.error;
  const stdout = result.stdout ?? "";
  if (!stdout.trim()) throw new Error(`curl returned empty response. stderr: ${result.stderr ?? ""}`);

  const gql = JSON.parse(stdout) as GitHubGraphQLResponse;
  if (gql.errors?.length) {
    throw new Error(`GraphQL errors: ${gql.errors.map((e) => e.message).join("; ")}`);
  }

  const pr = gql.data?.repository?.pullRequest;
  if (!pr) throw new Error("GraphQL response missing pullRequest data");

  const mergeableRaw = pr.mergeable;
  const mergeable =
    mergeableRaw === "MERGEABLE" ? true :
    mergeableRaw === "CONFLICTING" ? false : null;

  const hasOpenComments = pr.reviewThreads.nodes.some((t) => !t.isResolved);

  return {
    draft: pr.isDraft,
    mergeable,
    hasOpenComments,
  };
}


// ── Public API ────────────────────────────────────────────────────────────────

/**
 * Scan all watched workspaces for `in_review` tasks whose PR URL is set,
 * then call the GitHub API for each to get current mergeability and draft state.
 *
 * Returns one `PrStatusResult` per task successfully polled.
 * Tasks with API errors or unparseable PR URLs are skipped (error emitted).
 */
export async function checkInReviewPrs(
  opts: CheckInReviewPrsOptions,
): Promise<PrStatusResult[]> {
  const { workspaceRoots, githubToken, emit } = opts;
  const results: PrStatusResult[] = [];

  for (const workspaceRoot of workspaceRoots) {
    const docsPath = featuresRoot(workspaceRoot);
    if (!existsSync(docsPath)) continue;

    let featureDirs: string[];
    try {
      featureDirs = readdirSync(docsPath, { withFileTypes: true })
        .filter((e) => e.isDirectory())
        .map((e) => e.name);
    } catch {
      continue;
    }

    for (const featureId of featureDirs) {
      const tasksDir = join(docsPath, featureId, TASKS_DIR);
      if (!existsSync(tasksDir)) continue;

      let taskFiles: string[];
      try {
        taskFiles = readdirSync(tasksDir).filter((f) =>
          /^T\d+\.yaml$/.test(f),
        );
      } catch {
        continue;
      }

      for (const fileName of taskFiles) {
        let task: Task;
        try {
          task = parseYaml(
            readFileSync(join(tasksDir, fileName), "utf-8"),
          ) as Task;
        } catch {
          continue;
        }

        // If the task is in-flight on main, the live state is on the feature branch.
        // If the branch doesn't exist yet, there's nothing to poll — skip.
        if (!TERMINAL_STATUSES.has(task.status)) {
          const taskId = fileName.replace(/\.yaml$/, "");
          const branch = taskBranchName(featureId, taskId);
          const relPath = taskYamlRelPath(featureId, taskId);
          const branchTask = tryReadTaskFromBranch(workspaceRoot, branch, relPath);
          if (!branchTask) continue;
          task = branchTask;
        }

        // Only poll in_review tasks with a PR URL set.
        if (task.status !== "in_review") continue;
        if (!task.pr?.url) continue;

        const coords = parsePrUrl(task.pr.url);
        if (!coords) {
          emit({
            type: "in_review_poll_error",
            task_id: task.id,
            feature_id: featureId,
            details: `Cannot parse PR URL: ${task.pr.url}`,
          });
          continue;
        }

        try {
          const prStatus = fetchPrStatus(
            coords.owner,
            coords.repo,
            coords.pullNumber,
            githubToken,
          );

          results.push({
            taskId: task.id,
            featureId,
            workspaceRoot,
            mergeable: prStatus.mergeable,
            draft: prStatus.draft,
            hasOpenComments: prStatus.hasOpenComments,
          });
        } catch (e) {
          emit({
            type: "in_review_poll_error",
            task_id: task.id,
            feature_id: featureId,
            details: String(e),
          });
        }
      }
    }
  }

  return results;
}

