/**
 * Tests for poll/check-in-review-prs.ts
 *
 * Unit tests only — no real GitHub API calls. `spawnSync` (used for both
 * `git show` branch-lookup and `curl` GitHub GraphQL calls) is mocked via vi.mock.
 * Filesystem operations use real temp directories.
 *
 * Covers:
 *   1. parsePrUrl — valid URL, invalid URL, no match
 *   2. checkInReviewPrs — returns results for in_review tasks with PR URL
 *   3. checkInReviewPrs — skips tasks that are not in_review
 *   4. checkInReviewPrs — skips tasks with no PR URL
 *   5. checkInReviewPrs — emits in_review_poll_error on unparseable PR URL
 *   6. checkInReviewPrs — emits in_review_poll_error on GraphQL errors / curl failure
 *   7. checkInReviewPrs — reads task YAML from feature branch when main is non-terminal
 *   8. checkInReviewPrs — hasOpenComments (inline threads only)
 */

import { describe, it, expect, vi, afterEach } from "vitest";
import {
  mkdtempSync,
  mkdirSync,
  writeFileSync,
  rmSync,
} from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { spawnSync } from "node:child_process";
import { stringify as yamlStringify } from "yaml";
import type { Task } from "../src/types/task.js";
import {
  parsePrUrl,
  checkInReviewPrs,
} from "../src/poll/check-in-review-prs.js";

// ── Mock node:child_process (spawnSync only) ──────────────────────────────────

vi.mock("node:child_process", async (importOriginal) => {
  const actual =
    await importOriginal<typeof import("node:child_process")>();
  return { ...actual, spawnSync: vi.fn() };
});

// ── Fixtures ──────────────────────────────────────────────────────────────────

const FEATURE_ID = "my-feature";
const TASK_ID = "T3";
const SAMPLE_PR_URL = "https://github.com/myorg/my-impl-repo/pull/42";
const GITHUB_TOKEN = "ghp_test";

function makeTask(overrides: Partial<Task> = {}): Task {
  return {
    id: TASK_ID,
    title: "My Task",
    repo: "my-impl-repo",
    status: "in_review",
    depends_on: [],
    blocked_reason: null,
    blocked_context: null,
    branch: `feature/${FEATURE_ID}-${TASK_ID}`,
    execution: {
      actor_type: "agent",
      last_updated_by: "agent@test.com",
      last_updated_at: "2026-04-15T00:00:00Z",
    },
    pr: { url: SAMPLE_PR_URL, status: "open" },
    workspace_pr: null,
    log: [],
    ...overrides,
  };
}

// ── Temp directory helpers ────────────────────────────────────────────────────

const tmpDirs: string[] = [];

function makeWorkspaceWithTask(task: Task, featureId = FEATURE_ID): string {
  const dir = mkdtempSync(join(tmpdir(), "check-pr-unit-"));
  tmpDirs.push(dir);
  const tasksDir = join(dir, "docs", "features", featureId, "tasks");
  mkdirSync(tasksDir, { recursive: true });
  writeFileSync(join(tasksDir, `${task.id}.yaml`), yamlStringify(task), "utf-8");
  return dir;
}

afterEach(() => {
  while (tmpDirs.length) {
    const d = tmpDirs.pop()!;
    try { rmSync(d, { recursive: true, force: true }); } catch { /* best-effort */ }
  }
  vi.clearAllMocks();
});

// ── Mock helpers ──────────────────────────────────────────────────────────────

type ReviewThread = { isResolved: boolean };

function mockGraphQL(opts: {
  isDraft?: boolean;
  mergeable?: "MERGEABLE" | "CONFLICTING" | "UNKNOWN";
  reviewThreads?: ReviewThread[];
}): ReturnType<typeof spawnSync> {
  const body = {
    data: {
      repository: {
        pullRequest: {
          isDraft: opts.isDraft ?? false,
          mergeable: opts.mergeable ?? "MERGEABLE",
          reviewThreads: { nodes: opts.reviewThreads ?? [] },
        },
      },
    },
  };
  return {
    pid: 0, output: [], stdout: JSON.stringify(body),
    stderr: "", status: 0, signal: null, error: undefined,
  } as unknown as ReturnType<typeof spawnSync>;
}

function mockGraphQLError(message: string): ReturnType<typeof spawnSync> {
  return {
    pid: 0, output: [],
    stdout: JSON.stringify({ errors: [{ message }] }),
    stderr: "", status: 0, signal: null, error: undefined,
  } as unknown as ReturnType<typeof spawnSync>;
}

function mockCurlFailure(message: string): ReturnType<typeof spawnSync> {
  return {
    pid: 0, output: [], stdout: "", stderr: message, status: 1, signal: null,
    error: new Error(message),
  } as unknown as ReturnType<typeof spawnSync>;
}

function mockGitShowTask(task: Task): ReturnType<typeof spawnSync> {
  return {
    pid: 0, output: [], stdout: yamlStringify(task),
    stderr: "", status: 0, signal: null, error: undefined,
  } as unknown as ReturnType<typeof spawnSync>;
}

function mockGitShowNotFound(): ReturnType<typeof spawnSync> {
  return {
    pid: 0, output: [], stdout: "", stderr: "fatal: Path not found",
    status: 128, signal: null, error: undefined,
  } as unknown as ReturnType<typeof spawnSync>;
}

// ── 1. parsePrUrl ─────────────────────────────────────────────────────────────

describe("parsePrUrl", () => {
  it("parses a standard GitHub PR URL", () => {
    expect(parsePrUrl("https://github.com/myorg/my-repo/pull/42"))
      .toEqual({ owner: "myorg", repo: "my-repo", pullNumber: 42 });
  });

  it("parses PR URL with http scheme", () => {
    expect(parsePrUrl("http://github.com/owner/repo/pull/1"))
      .toEqual({ owner: "owner", repo: "repo", pullNumber: 1 });
  });

  it("returns null for an SSH URL", () => {
    expect(parsePrUrl("git@github.com:owner/repo.git")).toBeNull();
  });

  it("returns null for a non-PR URL", () => {
    expect(parsePrUrl("https://github.com/owner/repo")).toBeNull();
  });

  it("returns null for an empty string", () => {
    expect(parsePrUrl("")).toBeNull();
  });

  it("handles large pull numbers", () => {
    expect(parsePrUrl("https://github.com/org/repo/pull/9999")?.pullNumber).toBe(9999);
  });
});

// ── 2. checkInReviewPrs — happy path ─────────────────────────────────────────

describe("checkInReviewPrs — happy path", () => {
  it("returns a PrStatusResult for each in_review task with a PR URL", async () => {
    const task = makeTask();
    const wsRoot = makeWorkspaceWithTask(task);
    vi.mocked(spawnSync)
      .mockReturnValueOnce(mockGitShowTask(task))
      .mockReturnValueOnce(mockGraphQL({ mergeable: "MERGEABLE", isDraft: false }));

    const events: Record<string, unknown>[] = [];
    const results = await checkInReviewPrs({
      workspaceRoots: [wsRoot],
      githubToken: GITHUB_TOKEN,
      emit: (e) => events.push(e),
    });

    expect(results).toHaveLength(1);
    expect(results[0]).toMatchObject({
      taskId: TASK_ID,
      featureId: FEATURE_ID,
      workspaceRoot: wsRoot,
      mergeable: true,
      draft: false,
      hasOpenComments: false,
    });
    expect(events).toHaveLength(0);
  });

  it("posts to the GraphQL endpoint with Bearer auth", async () => {
    const task = makeTask();
    const wsRoot = makeWorkspaceWithTask(task);
    vi.mocked(spawnSync)
      .mockReturnValueOnce(mockGitShowTask(task))
      .mockReturnValueOnce(mockGraphQL({ mergeable: "CONFLICTING" }));

    await checkInReviewPrs({ workspaceRoots: [wsRoot], githubToken: GITHUB_TOKEN, emit: () => {} });

    const [, args] = vi.mocked(spawnSync).mock.calls[1];
    const argsArray = args as string[];
    expect(argsArray.some((a) => a.includes("Authorization: Bearer"))).toBe(true);
    expect(argsArray.some((a) => a.includes("api.github.com/graphql"))).toBe(true);
    // Variables contain owner/repo/number
    const bodyArg = argsArray[argsArray.indexOf("-d") + 1];
    const parsed = JSON.parse(bodyArg);
    expect(parsed.variables).toMatchObject({ owner: "myorg", name: "my-impl-repo", number: 42 });
  });

  it("maps CONFLICTING to mergeable: false", async () => {
    const task = makeTask();
    const wsRoot = makeWorkspaceWithTask(task);
    vi.mocked(spawnSync)
      .mockReturnValueOnce(mockGitShowTask(task))
      .mockReturnValueOnce(mockGraphQL({ mergeable: "CONFLICTING" }));

    const results = await checkInReviewPrs({ workspaceRoots: [wsRoot], githubToken: GITHUB_TOKEN, emit: () => {} });
    expect(results[0].mergeable).toBe(false);
  });

  it("maps UNKNOWN to mergeable: null", async () => {
    const task = makeTask();
    const wsRoot = makeWorkspaceWithTask(task);
    vi.mocked(spawnSync)
      .mockReturnValueOnce(mockGitShowTask(task))
      .mockReturnValueOnce(mockGraphQL({ mergeable: "UNKNOWN" }));

    const results = await checkInReviewPrs({ workspaceRoots: [wsRoot], githubToken: GITHUB_TOKEN, emit: () => {} });
    expect(results[0].mergeable).toBeNull();
  });

  it("maps isDraft: true correctly", async () => {
    const task = makeTask();
    const wsRoot = makeWorkspaceWithTask(task);
    vi.mocked(spawnSync)
      .mockReturnValueOnce(mockGitShowTask(task))
      .mockReturnValueOnce(mockGraphQL({ isDraft: true }));

    const results = await checkInReviewPrs({ workspaceRoots: [wsRoot], githubToken: GITHUB_TOKEN, emit: () => {} });
    expect(results[0].draft).toBe(true);
  });

  it("returns results from multiple tasks across features", async () => {
    const task1 = makeTask({ id: "T1" });
    const task2 = makeTask({ id: "T2" });
    const wsRoot = mkdtempSync(join(tmpdir(), "check-pr-multi-"));
    tmpDirs.push(wsRoot);

    const makeTasksDir = (fid: string) => {
      const dir = join(wsRoot, "docs", "features", fid, "tasks");
      mkdirSync(dir, { recursive: true });
      return dir;
    };
    writeFileSync(join(makeTasksDir("feature-a"), "T1.yaml"), yamlStringify(task1));
    writeFileSync(join(makeTasksDir("feature-b"), "T2.yaml"), yamlStringify(task2));

    vi.mocked(spawnSync)
      .mockReturnValueOnce(mockGitShowTask(task1))
      .mockReturnValueOnce(mockGraphQL({ mergeable: "MERGEABLE" }))
      .mockReturnValueOnce(mockGitShowTask(task2))
      .mockReturnValueOnce(mockGraphQL({ mergeable: "CONFLICTING" }));

    const results = await checkInReviewPrs({ workspaceRoots: [wsRoot], githubToken: GITHUB_TOKEN, emit: () => {} });
    expect(results).toHaveLength(2);
  });
});

