/**
 * Tests for poll/handle-merged-prs.ts
 *
 * Unit tests only — no real git operations or GitHub API calls.
 * `execSync` and `spawnSync` are mocked via vi.mock.
 * Filesystem operations use real temp directories.
 *
 * Covers:
 *   1. handleMergedPrs — no-op when no results have merged: true
 *   2. handleMergedPrs — skips when live task status is not in_review (idempotency)
 *   3. handleMergedPrs — skips when tryReadTaskFromBranch returns null
 *   4. handleMergedPrs — happy path: marks done, merges workspace PR
 *   5. handleMergedPrs — workspace_pr: null → emits warning, skips merge step
 *   6. handleMergedPrs — workspace PR merge API error → emits failure, task YAML done retained
 *   7. handleMergedPrs — push rejection → emits pr_merge_done_blocked
 *   8. handleMergedPrs — auto-ready rule: activates sibling task when deps satisfied
 *   9. handleMergedPrs — re-checks status after checkout (second idempotency guard)
 */

import { describe, it, expect, vi, afterEach } from "vitest";
import {
  mkdtempSync,
  mkdirSync,
  writeFileSync,
  readFileSync,
  rmSync,
} from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { execSync, spawnSync } from "node:child_process";
import { stringify as yamlStringify, parse as parseYaml } from "yaml";
import type { Task } from "../src/types/task.js";
import type { PrStatusResult } from "../src/poll/check-in-review-prs.js";
import { handleMergedPrs, type HandleMergedPrsOptions } from "../src/poll/handle-merged-prs.js";

// ── Mock node:child_process ───────────────────────────────────────────────────

vi.mock("node:child_process", async (importOriginal) => {
  const actual = await importOriginal<typeof import("node:child_process")>();
  return { ...actual, execSync: vi.fn(), spawnSync: vi.fn() };
});

// ── Fixtures ──────────────────────────────────────────────────────────────────

const FEATURE_ID = "test-feature";
const TASK_ID = "T1";
const TASK_BRANCH = `feature/${FEATURE_ID}-${TASK_ID}`;
const GIT_AUTHOR_EMAIL = "agent@test.com";
const GIT_AUTHOR_NAME = "Agent Test";
const GITHUB_TOKEN = "ghp_test";
const MGMT_OWNER = "myorg";
const MGMT_REPO = "project-workspace";
const WORKSPACE_PR_URL = `https://github.com/${MGMT_OWNER}/${MGMT_REPO}/pull/55`;
const IMPL_PR_URL = "https://github.com/myorg/my-impl-repo/pull/42";

function makeTask(overrides: Partial<Task> = {}): Task {
  return {
    id: TASK_ID,
    title: "My Task",
    repo: "impl-repo",
    status: "in_review",
    depends_on: [],
    blocked_reason: null,
    blocked_context: null,
    branch: TASK_BRANCH,
    execution: {
      actor_type: "agent",
      last_updated_by: GIT_AUTHOR_EMAIL,
      last_updated_at: "2026-04-15T00:00:00Z",
    },
    pr: { url: IMPL_PR_URL, status: "open" },
    workspace_pr: { url: WORKSPACE_PR_URL, status: "open" },
    log: [],
    ...overrides,
  };
}

function makePrResult(overrides: Partial<PrStatusResult> = {}): PrStatusResult {
  return {
    taskId: TASK_ID,
    featureId: FEATURE_ID,
    workspaceRoot: "/mock/workspace",
    mergeable: true,
    draft: false,
    merged: true,
    hasOpenComments: false,
    ...overrides,
  };
}

// ── Temp directory helpers ────────────────────────────────────────────────────

const tmpDirs: string[] = [];

function makeWorkspaceWithTask(task: Task, featureId = FEATURE_ID): string {
  const dir = mkdtempSync(join(tmpdir(), "handle-merged-unit-"));
  tmpDirs.push(dir);
  const tasksDir = join(dir, "docs", "features", featureId, "tasks");
  mkdirSync(tasksDir, { recursive: true });
  writeFileSync(join(tasksDir, `${task.id}.yaml`), yamlStringify(task), "utf-8");
  return dir;
}

afterEach(() => {
  while (tmpDirs.length) {
    const d = tmpDirs.pop()!;
    try { rmSync(d, { recursive: true, force: true }); } catch { /* best-effort */ }
  }
  vi.clearAllMocks();
});

// ── Mock helpers ──────────────────────────────────────────────────────────────

/** Mock spawnSync for: git show → task YAML, git push → success, curl → success. */
function mockGitShowTask(task: Task): ReturnType<typeof spawnSync> {
  return {
    pid: 0, output: [], stdout: yamlStringify(task),
    stderr: "", status: 0, signal: null, error: undefined,
  } as unknown as ReturnType<typeof spawnSync>;
}

function mockGitShowNotFound(): ReturnType<typeof spawnSync> {
  return {
    pid: 0, output: [], stdout: "",
    stderr: "fatal: Path not found", status: 128, signal: null, error: undefined,
  } as unknown as ReturnType<typeof spawnSync>;
}

function mockPushSuccess(): ReturnType<typeof spawnSync> {
  return {
    pid: 0, output: [], stdout: "",
    stderr: "", status: 0, signal: null, error: undefined,
  } as unknown as ReturnType<typeof spawnSync>;
}

function mockPushRejected(): ReturnType<typeof spawnSync> {
  return {
    pid: 0, output: [], stdout: "",
    stderr: "! [rejected] main -> main (non-fast-forward)", status: 1, signal: null, error: undefined,
  } as unknown as ReturnType<typeof spawnSync>;
}

function mockCurlMergeSuccess(): ReturnType<typeof spawnSync> {
  return {
    pid: 0, output: [],
    stdout: JSON.stringify({ sha: "abc123", merged: true, message: "Pull Request successfully merged" }),
    stderr: "", status: 0, signal: null, error: undefined,
  } as unknown as ReturnType<typeof spawnSync>;
}

function mockCurlMergeFailure(message: string): ReturnType<typeof spawnSync> {
  return {
    pid: 0, output: [],
    stdout: JSON.stringify({ message }),
    stderr: "", status: 0, signal: null, error: undefined,
  } as unknown as ReturnType<typeof spawnSync>;
}

function makeBaseOpts(workspaceRoot: string, extra: Partial<HandleMergedPrsOptions> = {}): HandleMergedPrsOptions {
  return {
    prResults: [makePrResult({ workspaceRoot })],
    workspaceRoot,
    mgmtRepoOwner: MGMT_OWNER,
    mgmtRepoName: MGMT_REPO,
    githubToken: GITHUB_TOKEN,
    gitAuthorEmail: GIT_AUTHOR_EMAIL,
    gitAuthorName: GIT_AUTHOR_NAME,
    emit: () => {},
    ...extra,
  };
}

// ── 1. No-op when no merged results ──────────────────────────────────────────

describe("handleMergedPrs — no merged results", () => {
  it("does nothing when no prResults have merged: true", async () => {
    const wsRoot = makeWorkspaceWithTask(makeTask());
    const opts = makeBaseOpts(wsRoot, {
      prResults: [makePrResult({ workspaceRoot: wsRoot, merged: false })],
    });

    await handleMergedPrs(opts);

    expect(vi.mocked(execSync)).not.toHaveBeenCalled();
    expect(vi.mocked(spawnSync)).not.toHaveBeenCalled();
  });

  it("does nothing when prResults is empty", async () => {
    const wsRoot = makeWorkspaceWithTask(makeTask());
    const opts = makeBaseOpts(wsRoot, { prResults: [] });

    await handleMergedPrs(opts);

    expect(vi.mocked(execSync)).not.toHaveBeenCalled();
  });
});

// ── 2. Idempotency: skip non-in_review tasks ──────────────────────────────────

describe("handleMergedPrs — idempotency guard (live branch state)", () => {
  it("skips when live task status is done", async () => {
    const doneTask = makeTask({ status: "done" });
    const wsRoot = makeWorkspaceWithTask(doneTask);
    // spawnSync: first call is git show (tryReadTaskFromBranch)
    vi.mocked(spawnSync).mockReturnValueOnce(mockGitShowTask(doneTask));

    const events: Record<string, unknown>[] = [];
    await handleMergedPrs(makeBaseOpts(wsRoot, {
      prResults: [makePrResult({ workspaceRoot: wsRoot })],
      emit: (e) => events.push(e),
    }));

    expect(events.some((e) => e.type === "pr_merge_skip")).toBe(true);
    const skipEvent = events.find((e) => e.type === "pr_merge_skip");
    expect(String(skipEvent?.reason)).toContain("task_already_done");
    // execSync (git checkout etc.) should not have been called
    expect(vi.mocked(execSync)).not.toHaveBeenCalled();
  });

  it("skips when live task status is cancelled", async () => {
    const cancelledTask = makeTask({ status: "cancelled" });
    const wsRoot = makeWorkspaceWithTask(cancelledTask);
    vi.mocked(spawnSync).mockReturnValueOnce(mockGitShowTask(cancelledTask));

    const events: Record<string, unknown>[] = [];
    await handleMergedPrs(makeBaseOpts(wsRoot, {
      prResults: [makePrResult({ workspaceRoot: wsRoot })],
      emit: (e) => events.push(e),
    }));

    expect(events.some((e) => e.type === "pr_merge_skip")).toBe(true);
    expect(vi.mocked(execSync)).not.toHaveBeenCalled();
  });
});

// ── 3. Skips when feature branch not found ───────────────────────────────────

describe("handleMergedPrs — branch not found", () => {
  it("emits pr_merge_skip with task_branch_not_found when git show fails", async () => {
    const wsRoot = makeWorkspaceWithTask(makeTask());
    vi.mocked(spawnSync).mockReturnValueOnce(mockGitShowNotFound());

    const events: Record<string, unknown>[] = [];
    await handleMergedPrs(makeBaseOpts(wsRoot, {
      prResults: [makePrResult({ workspaceRoot: wsRoot })],
      emit: (e) => events.push(e),
    }));

    expect(events[0].type).toBe("pr_merge_skip");
    expect(events[0].reason).toBe("task_branch_not_found");
  });
});

// ── 4. Happy path: marks done, merges workspace PR ───────────────────────────

describe("handleMergedPrs — happy path", () => {
  it("marks task done, updates pr.status to merged, appends log entry, merges workspace PR", async () => {
    const task = makeTask();
    const wsRoot = makeWorkspaceWithTask(task);

    // spawnSync calls: git show (tryReadTaskFromBranch), git push, curl merge
    vi.mocked(spawnSync)
      .mockReturnValueOnce(mockGitShowTask(task))   // tryReadTaskFromBranch
      .mockReturnValueOnce(mockPushSuccess())        // git push
      .mockReturnValueOnce(mockCurlMergeSuccess()); // curl PUT merge

    // execSync calls: git fetch, git checkout, git pull, git add, git commit
    vi.mocked(execSync).mockReturnValue(undefined as unknown as Buffer);

    const events: Record<string, unknown>[] = [];
    await handleMergedPrs(makeBaseOpts(wsRoot, {
      prResults: [makePrResult({ workspaceRoot: wsRoot })],
      emit: (e) => events.push(e),
    }));

    // Verify task YAML was updated on disk.
    const updatedTask = parseYaml(
      readFileSync(join(wsRoot, "docs", "features", FEATURE_ID, "tasks", `${TASK_ID}.yaml`), "utf-8"),
    ) as Task;

    expect(updatedTask.status).toBe("done");
    expect(updatedTask.pr.status).toBe("merged");
    expect(updatedTask.log.some((e) => e.action === "done")).toBe(true);
    const doneEntry = updatedTask.log.find((e) => e.action === "done");
    expect(doneEntry?.note).toBe("Implementation PR merged — automated close-out by pr-merge loop.");
    expect(doneEntry?.by).toBe(GIT_AUTHOR_EMAIL);

    // Verify events.
    expect(events.some((e) => e.type === "task_marked_done")).toBe(true);
    expect(events.some((e) => e.type === "workspace_pr_merged")).toBe(true);
  });

  it("calls git fetch, checkout, pull in correct order", async () => {
    const task = makeTask();
    const wsRoot = makeWorkspaceWithTask(task);
    vi.mocked(spawnSync)
      .mockReturnValueOnce(mockGitShowTask(task))
      .mockReturnValueOnce(mockPushSuccess())
      .mockReturnValueOnce(mockCurlMergeSuccess());
    vi.mocked(execSync).mockReturnValue(undefined as unknown as Buffer);

    await handleMergedPrs(makeBaseOpts(wsRoot, {
      prResults: [makePrResult({ workspaceRoot: wsRoot })],
    }));

    const execCalls = vi.mocked(execSync).mock.calls.map((c) => String(c[0]));
    expect(execCalls.some((c) => c.includes("fetch origin"))).toBe(true);
    expect(execCalls.some((c) => c.includes(`checkout "${TASK_BRANCH}"`))).toBe(true);
    expect(execCalls.some((c) => c.includes(`pull origin "${TASK_BRANCH}"`))).toBe(true);
  });

  it("uses the correct PUT URL for workspace PR merge", async () => {
    const task = makeTask();
    const wsRoot = makeWorkspaceWithTask(task);
    vi.mocked(spawnSync)
      .mockReturnValueOnce(mockGitShowTask(task))
      .mockReturnValueOnce(mockPushSuccess())
      .mockReturnValueOnce(mockCurlMergeSuccess());
    vi.mocked(execSync).mockReturnValue(undefined as unknown as Buffer);

    await handleMergedPrs(makeBaseOpts(wsRoot, {
      prResults: [makePrResult({ workspaceRoot: wsRoot })],
    }));

    const curlCall = vi.mocked(spawnSync).mock.calls.find(
      ([cmd]) => cmd === "curl",
    );
    expect(curlCall).toBeDefined();
    const curlArgs = curlCall![1] as string[];
    const url = curlArgs[curlArgs.length - 1];
    expect(url).toContain(`/repos/${MGMT_OWNER}/${MGMT_REPO}/pulls/55/merge`);
  });
});

